			Application.Current.Resources.MergedDictionaries.Add(val);
			Application.Current.Resources.MergedDictionaries.Add(BRComponentResources.SingleInstance.ResourceDictionary);
		}

		public override FrameworkElement CreateControl(IMessageBox iMsg)
		{
			GlobalFun.DeleteDirectory(Configurations.AppIconCacheDir);
			LogHelper.LogInstance.Debug("Clear app icon cache.", false);
			MainFrameV6 mainFrameV = new MainFrameV6();
			((FrameworkElement)mainFrameV).DataContext = Context.MainFrame;
