		{
			return Context.IsExecuteWork;
		}

		public override void OnInit(object data)
		{
			((PluginBase)this).OnInit(data);
			IList<DeviceEx> conntectedDevices = HostProxy.deviceManager.ConntectedDevices;
			if (conntectedDevices == null || conntectedDevices.Count((DeviceEx n) => (int)n.ConnectType != 2 && (int)n.SoftStatus == 2) == 0)
			{
				Context.MainFrame.SelectedNav = null;
			}
		}

		public override bool IsNonBusinessPage()
		{
			return list.Contains(Context.CurrentViewType);
