		private async void ExportAppCommandHandler(object prameter)
		{
			if (!(prameter is ObservableCollection<AppInfoModel> source))
			{
				return;
			}
			FolderBrowserDialog val = new FolderBrowserDialog();
			val.Description = LangTranslation.Translate("K0651");
			if ((int)((CommonDialog)val).ShowDialog() == 1)
			{
				if (!string.IsNullOrEmpty(val.SelectedPath))
				{
					_ExportAppCacheDirectory = val.SelectedPath;
				}
				List<string> list = (from n in source
					where n.IsSelected
					select n.PackageName).ToList();
				await new ImportAndExportWrapper().ExportFile((BusinessType)1120, 18, list, ResourcesHelper.StringResources.SingleInstance.APP_EXPORT_MESSAGE, "{958781C8-0788-4F87-A4C3-CBD793AAB1A0}", ResourcesHelper.StringResources.SingleInstance.APP_CONTENT, _ExportAppCacheDirectory, (Func<string, Header, string>)((string id, Header header) => Path.Combine(_ExportAppCacheDirectory, id + ".apk")));
			}
		}

		private async Task<bool> PrevCheck(string title, string content)
		{
			DeviceEx masterDevice = HostProxy.deviceManager.MasterDevice;
			if (masterDevice != null && (int)masterDevice.ConnectType == 4)
			{
				await MessageWindowHelper.Instance.Show(title, content, "K0327", (string)null, false, (MessageBoxImage)64, (string)null, false, false, false, (Action<IMessageWindowV6>)null, (Predicate<object>)null, (Predicate<object>)null, (Func<bool>)null, (bool?)true, false);
				return false;
			}
			return true;
		}

		public async void UninstallAppSingle(AppInfoModel appinfo)
		{
			if (await PrevCheck(ResourcesHelper.StringResources.SingleInstance.APP_UNINSTALL_TITLE, ResourcesHelper.StringResources.SingleInstance.APP_UNINSTALL_CONTENT))
			{
				bool? flag = await MessageWindowHelper.Instance.Show(ResourcesHelper.StringResources.SingleInstance.UNINSTALL_CONFIRM_TITLE, ResourcesHelper.StringResources.SingleInstance.UNINSTALL_SINGAL_APP_CONTENT, "K0485", "K0208", false, (MessageBoxImage)64, (string)null, false, false, false, (Action<IMessageWindowV6>)null, (Predicate<object>)null, (Predicate<object>)null, (Func<bool>)null, (bool?)true, false);
				if (flag.HasValue && flag.Value)
				{
					List<string> list = new List<string>();
					list.Add(appinfo.PackageName);
					UninstallV6(list);
				}
			}
		}

		private async void UninstallAppCommandHandler(object prameter)
		{
			if (!(await PrevCheck(ResourcesHelper.StringResources.SingleInstance.APP_UNINSTALL_TITLE, ResourcesHelper.StringResources.SingleInstance.APP_UNINSTALL_CONTENT)) || !(prameter is ObservableCollection<AppInfoModel> appList))
			{
				return;
			}
			bool? flag = await MessageWindowHelper.Instance.Show(ResourcesHelper.StringResources.SingleInstance.UNINSTALL_CONFIRM_TITLE, ResourcesHelper.StringResources.SingleInstance.UNINSTALL_APP_CONTENT, "K0485", "K0208", false, (MessageBoxImage)64, (string)null, false, false, false, (Action<IMessageWindowV6>)null, (Predicate<object>)null, (Predicate<object>)null, (Func<bool>)null, (bool?)true, false);
			if (flag.HasValue && flag.Value)
			{
				List<string> packagenames = (from n in appList
					where n.IsSelected
					select n.PackageName).ToList();
				UninstallV6(packagenames);
			}
		}

