		private void SingleMouseClickCommandHandler()
		{
			ObservableCollection<ContactItemViewModelV6> contactPagingList = GetCurrentViewModel.ContactPagingList;
			if (isSelected)
			{
				if (contactPagingList.Count((ContactItemViewModelV6 m) => !m.isSelected) > 0)
				{
					GetCurrentViewModel.IsPagingContactSelected = null;
				}
				else
				{
					GetCurrentViewModel.IsPagingContactSelected = true;
				}
			}
			else if (contactPagingList.Count((ContactItemViewModelV6 m) => m.isSelected) > 0)
			{
				GetCurrentViewModel.IsPagingContactSelected = null;
			}
			else
			{
				GetCurrentViewModel.IsPagingContactSelected = false;
			}
			GetCurrentViewModel.RefreshSelectedCount();
			ContactItemViewModelV6 contactItemViewModelV = GetCurrentViewModel.ContactListOriginal.FirstOrDefault((ContactItemViewModelV6 m) => m.Id == Id);
			if (contactItemViewModelV != null)
			{
				contactItemViewModelV.isSelected = isSelected;
			}
		}
	}
