		private async void ExportContactCommandHandler(object prameter)
		{
			HidenAddPanel();
			HidenDetialPanel();
			FolderBrowserDialog val = new FolderBrowserDialog();
			if ((int)((CommonDialog)val).ShowDialog() != 1)
			{
				return;
			}
			string dir = val.SelectedPath.Trim();
			List<string> idList = (from m in ContactList
				where m.isSelected
				select m.Id).ToList();
			if (idList.Count <= 0)
			{
				return;
			}
			await new ImportAndExportWrapper().ExportString((BusinessType)1520, 23, "K0533", "{5A60E6A0-35DE-4EA5-926E-96C15B54DDF6}", BackupRestoreStaticResources.SingleInstance.CONTACT, (Func<IAsyncTaskContext, List<string>>)((IAsyncTaskContext taskContext) => idList), (Action<Action<Action<string>>>)delegate(Action<Action<string>> trigger)
			{
				System.IO.FileInfo fileInfo = new System.IO.FileInfo(Path.Combine(dir, "contacts_" + DateTime.Now.ToString("yyyyMMddHHmmss") + ".vcf"));
				StreamWriter writer = new StreamWriter(fileInfo.Create());
				try
				{
					trigger(delegate(string str)
					{
						writer.WriteLine(str);
					});
				}
				finally
				{
					if (writer != null)
					{
						((IDisposable)writer).Dispose();
					}
				}
			});
		}

		private async void ImportContactCommandHandler(object prameter)
		{
			HidenAddPanel();
			HidenDetialPanel();
			OpenFileDialog dlg = new OpenFileDialog();
			((FileDialog)dlg).Title = "K0496";
			if (HostProxy.LanguageService.IsNeedTranslate())
			{
				((FileDialog)dlg).Title = HostProxy.LanguageService.Translate("K0496");
			}
			((FileDialog)dlg).Filter = string.Format("{0}|*.vcf", HostProxy.LanguageService.Translate("K0478"));
			dlg.Multiselect = false;
			((FileDialog)dlg).FileName = string.Empty;
			((FileDialog)dlg).FilterIndex = 1;
			if (((CommonDialog)dlg).ShowDialog() != true)
			{
				return;
			}
			ImportAndExportWrapper val = new ImportAndExportWrapper();
			Func<List<string>> func = delegate
			{
				System.IO.FileInfo fileInfo = new System.IO.FileInfo(((FileDialog)dlg).FileName);
				List<string> list = null;
				try
				{
					using StreamReader streamReader = new StreamReader(fileInfo.OpenRead());
					list = new List<string>();
					StringBuilder stringBuilder = new StringBuilder();
					string empty = string.Empty;
					while ((empty = streamReader.ReadLine()) != null)
					{
						stringBuilder.AppendLine(empty);
						if ("END:VCARD".Equals(empty))
						{
							list.Add(stringBuilder.ToString());
							stringBuilder.Clear();
						}
					}
				}
				catch (Exception ex)
				{
					LogHelper.LogInstance.Error("Import contact throw ex:" + ex, false);
					list = null;
				}
				return list;
			};
			await val.ImportString((BusinessType)1510, 23, "K0532", "{5A60E6A0-35DE-4EA5-926E-96C15B54DDF6}", BackupRestoreStaticResources.SingleInstance.CONTACT, func);
			RefreshContacts();
		}

		private async void DelContactCommandHandler(object prameter)
		{
			HidenAddPanel();
			HidenDetialPanel();
			if (await MessageWindowHelper.Instance.Show("K0711", "K0534", "K0327", "K0208", false, (MessageBoxImage)64, (string)null, false, false, false, (Action<IMessageWindowV6>)null, (Predicate<object>)null, (Predicate<object>)null, (Func<bool>)null, (bool?)true, false) != true)
			{
				return;
			}
			List<string> dellist = (from m in ContactList
				where m.isSelected
				select m.Id).ToList();
			if (dellist.Count > 0)
			{
				bool success = false;
				await AsyncDataLoader.Loading((Action)delegate
				{
					//IL_0017: Unknown result type (might be due to invalid IL or missing references)
					//IL_001d: Expected O, but got Unknown
					Stopwatch stopwatch = new Stopwatch();
					stopwatch.Start();
					BusinessData val = new BusinessData((BusinessType)1530, Context.CurrentDevice, (BusinessStatus)0);
					success = mgt.DeleteContact(dellist);
					stopwatch.Stop();
					HostProxy.BehaviorService.Collect((BusinessType)1530, val.Update(stopwatch.ElapsedMilliseconds, (BusinessStatus)(success ? 10 : 20), (object)dellist));
				});
				if (success)
				{
					RefreshContacts();
				}
			}
		}

