			{
				contactPaging.IsNotUserClick = true;
				contactPaging.isSelected = isSelected;
				contactPaging.IsNotUserClick = false;
			}
			RefreshSelectedCount();
		}

		private void BatchLoadingContactData(List<string> _ids)
		{
			int num = 0;
			List<string> list = null;
			while (true)
			{
				list = _ids.Skip(num * 500).Take(500).ToList();
				if (list.Count == 0)
				{
					break;
				}
				List<Contact> contactListByContactId = mgt.getContactListByContactId(list);
				if (contactListByContactId == null)
				{
					break;
				}
				FillContactProperty(contactListByContactId);
				num++;
			}
		}

		private void FillContactProperty(List<Contact> _serverData)
		{
			ContactItemViewModelV6 contactItemViewModelV = null;
			foreach (Contact _serverDatum in _serverData)
			{
				contactItemViewModelV = new ContactItemViewModelV6();
				contactItemViewModelV.Id = _serverDatum.Id;
				contactItemViewModelV.Name = _serverDatum.Name;
				contactItemViewModelV.Number = _serverDatum.Number;
				contactItemViewModelV.Acronym = _serverDatum.Acronym;
				contactItemViewModelV.SortKey = _serverDatum.SortKey;
				contactItemViewModelV.Type = _serverDatum.Type;
				contactItemViewModelV.IsNotUserClick = true;
				List<Phone> numberList = _serverDatum.NumberList;
				if (numberList != null && numberList.Count > 0)
				{
					List<ContactItemPhoneViewModelV6> list = new List<ContactItemPhoneViewModelV6>();
					foreach (Phone number in _serverDatum.NumberList)
					{
						list.Add(new ContactItemPhoneViewModelV6
						{
							Content = number.PhoneNumber,
							Type = number.PhoneType
						});
					}
					contactItemViewModelV.NumberList = list;
				}
				ContactList.Add(contactItemViewModelV);
			}
		}

		private async void RefreshContacts()
		{
			IsAllContactSelected = false;
			IsPagingContactSelected = false;
			ContactTotalCount = 0;
			SelectContactCount = 0;
			SearchText = string.Empty;
			Total = 0;
			CurrentPage = 1;
			await AsyncDataLoader.Loading((Action)delegate
			{
				ContactList?.Clear();
				List<string> allContactsId = mgt.GetAllContactsId();
				if (allContactsId != null && allContactsId.Count > 0)
				{
					ContactTotalCount = allContactsId.Count;
					BatchLoadingContactData(allContactsId);
					ContactDataClone();
				}
				RefreshPageControlData();
				Thread.Sleep(500);
			});
		}

		private void HidenAddPanel()
		{
			ContactAddOrEditViewModel.ContactAddPanelVisibility = (Visibility)1;
		}

		private void HidenDetialPanel()
		{
			ContactDetailViewModel.ContactDetailVisibility = (Visibility)1;
		}

		private void ContactDataClone()
		{
			HostProxy.CurrentDispatcher.Invoke((Action)delegate
			{
				string text = JsonHelper.SerializeObject2Json((object)ContactList);
				ContactListOriginal = JsonHelper.DeserializeJson2Object<List<ContactItemViewModelV6>>(text);
				ContactList.ForEach(delegate(ContactItemViewModelV6 m)
				{
					m.IsNotUserClick = false;
				});
			});
		}

		public void RefreshSelectedCount()
		{
			SelectContactCount = ContactList.Count((ContactItemViewModelV6 m) => m.isSelected);
			IsAllContactSelected = SelectContactCount == ContactTotalCount;
			ContactExportToolBtnEnable = SelectContactCount > 0;
			ContactDeleteToolBtnEnable = SelectContactCount > 0;
			CheckAllInPagingDataGrid();
		}

		private void OnPageChangedCommand(object prameter)
		{
			RefreshPageControlData(_initData: false);
		}

		public void RefreshPageControlData(bool _initData = true)
		{
			LogHelper.LogInstance.Debug("Loadding contact paging data.", false);
			if (_initData)
			{
				Total = ContactList.Count;
			}
			List<ContactItemViewModelV6> list = ContactList.Skip((CurrentPage - 1) * PageSize).Take(PageSize).ToList();
			ContactPagingList = new ObservableCollection<ContactItemViewModelV6>(list);
			CheckAllInPagingDataGrid();
		}

		public void CheckAllInPagingDataGrid()
		{
			if (ContactPagingList.Count((ContactItemViewModelV6 m) => m.isSelected) == 0)
			{
				IsPagingContactSelected = false;
			}
			else if (ContactPagingList.Count((ContactItemViewModelV6 m) => !m.isSelected) == 0)
			{
				IsPagingContactSelected = true;
			}
			else
			{
				IsPagingContactSelected = null;
			}
		}
	}
