		private void LoadDeviceTreeAsync()
		{
			Task.Run(delegate
			{
				//IL_00fd: Unknown result type (might be due to invalid IL or missing references)
				//IL_0122: Expected O, but got Unknown
				//IL_009e: Unknown result type (might be due to invalid IL or missing references)
				//IL_00c3: Expected O, but got Unknown
				DeviceTreeSources = new ObservableCollection<TreeViewModel>();
				string internalPath = string.Empty;
				string externalPath = string.Empty;
				forwardStack.Clear();
				backStack.Clear();
				fileManager.GetInternalAndExternamPath(out internalPath, out externalPath);
				List<TreeViewModel> list = new List<TreeViewModel>();
				if (SdCarVm.StorageSelIndex == 0)
				{
					if (!string.IsNullOrEmpty(internalPath) && internalPath.Length > 0 && internalPath[0].Equals('/'))
					{
						list.Add((TreeViewModel)(object)new FileDataViewModel(new TreeModel(internalPath, (string)null, "Download", internalPath, (string)null), null, isFolder: true, 0L, null, null, DeviceFolderExpand));
					}
				}
				else if (!string.IsNullOrEmpty(externalPath) && externalPath.Length > 0 && externalPath[0].Equals('/'))
				{
					list.Add((TreeViewModel)(object)new FileDataViewModel(new TreeModel(externalPath, (string)null, "Download", externalPath, (string)null), null, isFolder: true, 0L, null, null, DeviceFolderExpand));
				}
				HostProxy.CurrentDispatcher.Invoke<ObservableCollection<TreeViewModel>>((Func<ObservableCollection<TreeViewModel>>)(() => DeviceTreeSources = new ObservableCollection<TreeViewModel>(list)));
				if (DeviceTreeSources.Count >= 1)
				{
					allDeviceChildrens = new List<FileDataViewModel>();
					TraverseChildren(DeviceTreeSources[0] as FileDataViewModel);
					for (int num = 0; num < allDeviceChildrens.Count; num++)
					{
						TraverseChildren(allDeviceChildrens[num]);
					}
					DeviceFileCount = allDeviceChildrens.Where((FileDataViewModel x) => !x.IsFolder).Count();
					DeviceTreeSources[0].ChildrenCount = DeviceFileCount;
					if (string.IsNullOrEmpty(CurDevicePath) || (CurPhoneSelected != null && CurPhoneSelected.Name == "Download"))
					{
						LoadDeviceChildrens(DeviceTreeSources[0], expand: false, refresh: true);
					}
					else
					{
						((TreeViewModel)(DeviceTreeSources[0] as FileDataViewModel)).IsExpanded = true;
						if (allDeviceChildrens.Where((FileDataViewModel x) => ((TreeViewModel)x).Data == CurDevicePath && x.IsFolder).Count() != 0)
						{
							LoadDeviceChildrens(allDeviceChildrens.Where((FileDataViewModel x) => ((TreeViewModel)x).Data == CurDevicePath && x.IsFolder).First(), expand: false, refresh: true);
						}
					}
					backStack.Push(DeviceTreeSources[0] as FileDataViewModel);
					Context.FileRefreshToolBtnEnable = true;
				}
			});
		}

