		private void LoadPcChildrens(object data, bool expand, bool refresh)
		{
			//IL_0134: Unknown result type (might be due to invalid IL or missing references)
			//IL_0164: Expected O, but got Unknown
			//IL_0212: Unknown result type (might be due to invalid IL or missing references)
			//IL_0249: Expected O, but got Unknown
			FileDataViewModel selected = data as FileDataViewModel;
			if (selected == null || !selected.IsFolder)
			{
				return;
			}
			List<FileDataViewModel> childrens = new List<FileDataViewModel>();
			if (selected == null || (!refresh && CurPcSelected != null && CurPcSelected.ID.Equals(((TreeViewModel)selected).ID) && CurPcSelected.Childrens.Count > 0))
			{
				return;
			}
			if (!expand)
			{
				CurPcSelected = (TreeViewModel)(object)selected;
			}
			if (selected.IsFolder)
			{
				string data2 = ((TreeViewModel)selected).Data;
				if (Directory.Exists(data2))
				{
					DirectoryInfo[] directories = new DirectoryInfo(data2).GetDirectories();
					foreach (DirectoryInfo directoryInfo in directories)
					{
						if (!directoryInfo.Attributes.HasFlag(FileAttributes.System) && !directoryInfo.Attributes.HasFlag(FileAttributes.Hidden))
						{
							childrens.Add(new FileDataViewModel(new TreeModel(directoryInfo.FullName, ((TreeViewModel)selected).ID, directoryInfo.Name, directoryInfo.FullName, (string)null), selected, isFolder: true, 0L, "Directory", directoryInfo.LastWriteTime, PcFolderExpand));
						}
					}
					foreach (string item in (from m in Directory.GetFiles(data2)
						orderby m
						select m).ToList())
					{
						System.IO.FileInfo fileInfo = new System.IO.FileInfo(item);
						if (!fileInfo.Attributes.HasFlag(FileAttributes.System) && !fileInfo.Attributes.HasFlag(FileAttributes.Hidden))
						{
							childrens.Add(new FileDataViewModel(new TreeModel(item, ((TreeViewModel)selected).ID, Path.GetFileName(item), item, (string)null), selected, isFolder: false, fileInfo.Length, fileInfo.Extension, fileInfo.LastWriteTime, PcFolderExpand));
						}
					}
				}
			}
			HostProxy.CurrentDispatcher.Invoke((Action)delegate
			{
				((TreeViewModel)selected).Childrens = new ObservableCollection<TreeViewModel>((IEnumerable<TreeViewModel>)childrens);
				if (!expand)
				{
					((TreeViewModel)selected).IsSelected = true;
					PcDataGridSources = new ObservableCollection<TreeViewModel>((IEnumerable<TreeViewModel>)childrens);
					CurPcPath = ((TreeViewModel)selected).Data;
				}
				((TreeViewModel)selected).IsExpanded = true;
			});
		}

		private void SetIsCheckForCheckbox()
		{
			if (string.IsNullOrEmpty(CurDevicePath))
			{
				return;
			}
			List<FileDataViewModel> list = allDeviceChildrens.Where((FileDataViewModel x) => ((TreeViewModel)x).Data.Contains(CurDevicePath)).ToList();
			for (int num = 0; num < list.Count(); num++)
			{
				if (list.Where((FileDataViewModel x) => ((TreeViewModel)x).IsChecked == true).Count() == 0)
				{
					IsAllCheckedForCheckBox = false;
				}
				else if (list.Where((FileDataViewModel x) => ((TreeViewModel)x).IsChecked == true).Count() == list.Count)
				{
					IsAllCheckedForCheckBox = true;
				}
				else
				{
					IsAllCheckedForCheckBox = null;
				}
			}
		}

		private void DeviceFolderExpand(object data)
		{
