		private void PcEnterPathCommandHandler(object data)
		{
			string path = data?.ToString();
			if (string.IsNullOrEmpty(path))
			{
				return;
			}
			IsFireChanged = false;
			TreeViewModel val = PcTreeSources.FirstOrDefault((TreeViewModel n) => path.StartsWith(n.Data, StringComparison.CurrentCultureIgnoreCase));
			LoadPcChildrens(val, expand: false, refresh: true);
			string[] array = path.Substring(val.Data.Length).Split(new char[1] { Path.DirectorySeparatorChar }, StringSplitOptions.RemoveEmptyEntries);
			List<TreeViewModel> list = val.Childrens.ToList();
			string[] array2 = array;
			foreach (string text in array2)
			{
				foreach (TreeViewModel item in list)
				{
					if (text.Equals(item.Model.Name, StringComparison.CurrentCultureIgnoreCase))
					{
						item.ParentModel.IsSelected = false;
						LoadPcChildrens(item, expand: false, refresh: true);
						list = item.Childrens.ToList();
						break;
					}
					if (list.Count == 0)
					{
						break;
					}
				}
			}
			IsFireChanged = true;
		}

		private void TraverseChildren(FileDataViewModel parent)
		{
			//IL_00bf: Unknown result type (might be due to invalid IL or missing references)
			//IL_00f3: Expected O, but got Unknown
			if (parent == null || string.IsNullOrEmpty(((TreeViewModel)parent).Data) || !parent.IsFolder)
			{
				return;
			}
			List<DeviceFileInfo> filesInfo = fileManager.GetFilesInfo(((TreeViewModel)parent).Data);
			if (filesInfo == null || filesInfo.Count <= 0)
			{
				return;
			}
			foreach (DeviceFileInfo item in (from m in filesInfo
				orderby !m.BooleanIsFolder descending
				orderby m.RawFileName
				select m).ToList())
			{
				FileDataViewModel fileDataViewModel = new FileDataViewModel(new TreeModel(item.RawFilePath, ((TreeViewModel)parent).ID, item.RawFileName, item.RawFilePath, (string)null), parent, item.BooleanIsFolder, item.LongFileSize, item.RawFileType, item.DateTimeModifiedDate, DeviceFolderExpand);
				if (allDeviceChildrens.Contains(fileDataViewModel))
				{
					continue;
				}
				if (!fileDataViewModel.IsFolder)
				{
					allDeviceChildrens.Add(fileDataViewModel);
				}
				if (fileDataViewModel.IsFolder)
				{
					count = 0;
					FindChild(fileDataViewModel);
					((TreeViewModel)fileDataViewModel).ChildrenCount = count;
					if (((TreeViewModel)fileDataViewModel).ChildrenCount > 0)
					{
						allDeviceChildrens.Add(fileDataViewModel);
					}
					if ((from x in fileManager.GetFilesInfo(((TreeViewModel)fileDataViewModel).Data)
						where x.BooleanIsFolder
						select x).Count() == 0)
					{
						fileDataViewModel.IsVisible = (Visibility)1;
					}
				}
			}
		}

		public void FindChild(FileDataViewModel model)
		{
			//IL_00a0: Unknown result type (might be due to invalid IL or missing references)
			//IL_00ec: Expected O, but got Unknown
			if (!model.IsFolder)
			{
				return;
			}
			List<DeviceFileInfo> list = fileManager.GetFilesInfo(((TreeViewModel)model).Data).ToList();
			for (int i = 0; i < list.Count; i++)
			{
				if (list[i].BooleanIsFolder)
				{
					(from x in fileManager.GetFilesInfo(((TreeViewModel)model).Data)
						where !x.BooleanIsFolder
						select x).ToList();
					FileDataViewModel model2 = new FileDataViewModel(new TreeModel(list[i].RawFilePath, ((TreeViewModel)model).ID, list[i].RawFileName, list[i].RawFilePath, (string)null), model, list[i].BooleanIsFolder, list[i].LongFileSize, list[i].RawFileType, list[i].DateTimeModifiedDate, DeviceFolderExpand);
					FindChild(model2);
				}
				else
				{
					count++;
				}
			}
		}

		private void OnCheckedCommandHandler(object data)
		{
			if (data == null)
			{
				return;
			}
			try
			{
				FileDataViewModel selected = null;
				if (data is CheckBox)
				{
					selected = ((FrameworkElement)((data is CheckBox) ? data : null)).DataContext as FileDataViewModel;
					((TreeViewModel)selected).IsChecked = ((ToggleButton)((data is CheckBox) ? data : null)).IsChecked;
				}
				else
				{
					selected = data as FileDataViewModel;
				}
				if (selected == null)
				{
					LogHelper.LogInstance.Error("selected is null", false);
				}
				((TreeViewModel)selected).IsExpanded = true;
				((TreeViewModel)selected).IsSelected = true;
				if (((TreeViewModel)selected).Name == "Download")
				{
					for (int i = 0; i < allDeviceChildrens.Count; i++)
					{
						((TreeViewModel)allDeviceChildrens[i]).IsChecked = ((TreeViewModel)selected).IsChecked;
					}
				}
				if (selected != null && selected.IsFolder)
				{
					List<FileDataViewModel> list = allDeviceChildrens.Where((FileDataViewModel x) => ((TreeViewModel)x).Data.Contains(((TreeViewModel)selected).Data + "/")).ToList();
					for (int num = 0; num < list.Count; num++)
					{
						((TreeViewModel)list[num]).IsChecked = ((TreeViewModel)selected).IsChecked;
					}
				}
				if (selected != null && ((TreeViewModel)selected).IsChecked != true)
				{
					TreeViewModel parent = null;
					do
					{
						parent = ((TreeViewModel)selected).ParentModel;
						if (parent != null)
						{
							if (parent.Childrens.Where((TreeViewModel x) => x.IsChecked != false).Count() > 0)
							{
								parent.IsChecked = null;
							}
							else
							{
								parent.IsChecked = false;
							}
							selected = allDeviceChildrens.FindLast((FileDataViewModel x) => ((TreeViewModel)x).Data == parent.Data && ((TreeViewModel)x).Name == parent.Name);
						}
					}
					while (parent != null && parent.Name != "Download");
				}
				if (selected != null && ((TreeViewModel)selected).IsChecked == true)
				{
					TreeViewModel parent2 = null;
					do
					{
						parent2 = ((TreeViewModel)selected).ParentModel;
						if (parent2 == null)
						{
							continue;
						}
						bool flag = true;
						for (int num2 = 0; num2 < parent2.Childrens.Count; num2++)
						{
							if (parent2.Childrens[num2].IsChecked != true)
							{
								flag = false;
							}
						}
						if (flag)
						{
							parent2.IsChecked = true;
						}
						else
						{
							parent2.IsChecked = null;
						}
						selected = allDeviceChildrens.FindLast((FileDataViewModel x) => ((TreeViewModel)x).Data == parent2.Data && ((TreeViewModel)x).Name == parent2.Name);
					}
					while (parent2 != null && parent2.Name != "Download");
				}
				SetIsCheckForCheckbox();
				DeviceSelectFileCount = allDeviceChildrens.Where((FileDataViewModel x) => !x.IsFolder && ((TreeViewModel)x).IsChecked == true).Count();
				if (DeviceDataGridSources.Where((TreeViewModel x) => x.IsChecked == true).Count() == 0)
				{
					IsCurrentCheckBoxChecked = false;
				}
				else if (DeviceDataGridSources.Where((TreeViewModel x) => x.IsChecked == false).Count() == 0)
				{
					IsCurrentCheckBoxChecked = true;
				}
				else
				{
					IsCurrentCheckBoxChecked = null;
				}
			}
			catch (Exception ex)
			{
				LogHelper.LogInstance.Error("OnCheckedCommandHandler throw ex:" + ex, false);
			}
		}

		private void DeviceEnterPathCommandHandler(object data)
		{
			string path = data?.ToString();
			if (string.IsNullOrEmpty(path))
			{
				return;
			}
			IsFireChanged = false;
			TreeViewModel val = DeviceTreeSources.FirstOrDefault((TreeViewModel n) => path.StartsWith(n.Data, StringComparison.CurrentCultureIgnoreCase));
			if (backStack == null || backStack.Count == 0 || (backStack.Count > 0 && backStack.Peek() != allDeviceChildrens.Where((FileDataViewModel x) => ((TreeViewModel)x).Data == path).SingleOrDefault()))
			{
				backStack.Push(allDeviceChildrens.Where((FileDataViewModel x) => ((TreeViewModel)x).Data == path).SingleOrDefault());
			}
			LoadDeviceChildrens(val, expand: false, refresh: true);
			string[] array = path.Substring(val.Data.Length).Split(new char[1] { '/' }, StringSplitOptions.RemoveEmptyEntries);
			List<TreeViewModel> list = val.Childrens.ToList();
			string[] array2 = array;
			foreach (string text in array2)
			{
				foreach (TreeViewModel item in list)
				{
					if (text.Equals(item.Model.Name, StringComparison.CurrentCultureIgnoreCase))
					{
						item.ParentModel.IsSelected = false;
						LoadDeviceChildrens(item, expand: false, refresh: true);
						list = item.Childrens.ToList();
						break;
					}
					if (list.Count == 0)
					{
						break;
					}
				}
			}
			IsFireChanged = true;
		}
	}
