		public async void LoadMusic()
		{
			if (m_LockLoadingData)
			{
				return;
			}
			m_LockLoadingData = true;
			Dispatcher currentDispatcher = HostProxy.CurrentDispatcher;
			if (currentDispatcher != null)
			{
				currentDispatcher.Invoke((Action)delegate
				{
					AlbumsOriginal.Clear();
					FocusedAlbum.CachedAllMusics?.Clear();
					FocusedAlbum.IsSelectedAllMusics = false;
					FocusedAlbumPaging.CachedAllMusics?.Clear();
					FocusedAlbumPaging.IsSelectedAllMusics = false;
					AllAlbumMusicCount = 0;
					AllAlbumMusicSelectedCount = 0;
					Total = 0;
					IsSelectedAllAlbumMusic = false;
				});
			}
			await AsyncDataLoader.Loading((Action)delegate
			{
				List<MusicInfo> musicList = m_bll.GetMusicList("-1", -1, -1);
				UpdateAlbumList(musicList);
				Thread.Sleep(500);
			});
			m_LockLoadingData = false;
		}

