		private void SearchCommandHandler(object prameter)
		{
			if (prameter == null)
			{
				return;
			}
			foreach (MusicInfo _single in FocusedAlbum.CachedAllMusics)
			{
				FocusedAlbumOriginal.CachedAllMusics.First((MusicInfo m) => m.ID == _single.ID).IsSelected = _single.IsSelected;
			}
			string searchText = prameter.ToString().ToLower();
			FocusedAlbum.CachedAllMusics = new ObservableCollection<MusicInfo>(FocusedAlbumOriginal.CachedAllMusics.Where((MusicInfo m) => m.DisplayName.ToLower().Contains(searchText)));
			RefreshPageControlData();
		}

		private async void MusicToolImportCommandHandler(object parameter)
		{
			await m_bll.ImportMusicToDevice(FocusedAlbum?.AlbumPath);
			MusicToolRefreshCommandHandler(null);
		}

		private void MusicToolExportCommandHandler(object parameter)
		{
			List<string> list = new List<string>();
			Dictionary<string, long> dictionary = new Dictionary<string, long>();
			foreach (MusicAlbumViewModelV7 album in Albums)
			{
				foreach (MusicInfo cachedAllMusic in album.CachedAllMusics)
				{
					if (cachedAllMusic.IsSelected)
					{
						if (cachedAllMusic.Size > 4294967296L)
						{
							dictionary.Add(cachedAllMusic.RawMusicInfo.AlbumID, cachedAllMusic.Size);
						}
						else
						{
							list.Add(cachedAllMusic.RawMusicInfo.ID.ToString());
						}
					}
				}
			}
			DeviceCommonManagementV6.CheckExportFiles(dictionary);
			if (list.Count != 0)
			{
				m_bll.ExportDeviceMusic(list);
			}
		}

		private async void MusicToolDeleteCommandHandler(object parameter)
		{
			List<string> idList = new List<string>();
			foreach (MusicAlbumViewModelV7 album in Albums)
			{
				foreach (MusicInfo cachedAllMusic in album.CachedAllMusics)
				{
					if (cachedAllMusic.IsSelected)
					{
						idList.Add(cachedAllMusic.RawMusicInfo.ID.ToString());
					}
				}
			}
			if (idList.Count != 0)
			{
				bool? flag = await MessageWindowHelper.Instance.Show("K0711", ResourcesHelper.StringResources.SingleInstance.CONTACT_DELETE_TITLE, "K0327", "K0208", false, (MessageBoxImage)64, (string)null, false, false, false, (Action<IMessageWindowV6>)null, (Predicate<object>)null, (Predicate<object>)null, (Func<bool>)null, (bool?)true, false);
				if (flag.HasValue && flag.Value)
				{
					await m_bll.DeleteDeviceMusic(idList);
					MusicToolRefreshCommandHandler(null);
				}
			}
		}

		public void MusicToolRefreshCommandHandler(object parameter)
		{
			lock (this)
			{
				MusicToolDeleteBtn.IsEnabled = false;
				MusicToolExportBtn.IsEnabled = false;
			}
			try
			{
				IsSelectedAllAlbumMusic = false;
				SearchText = string.Empty;
				LoadMusic();
			}
			catch (Exception arg)
			{
				LogHelper.LogInstance.Error($"Refresh music list exception:{arg}", false);
				ReSetPicToolBtnStatus();
			}
		}

		public void SetToolBarEnable()
		{
			if (FocusedAlbum == null)
			{
				return;
			}
			Dispatcher currentDispatcher = HostProxy.CurrentDispatcher;
			if (currentDispatcher == null)
			{
				return;
			}
			currentDispatcher.Invoke((Action)delegate
			{
				bool isEnabled = FocusedAlbum.CachedAllMusics.Any((MusicInfo p) => p.IsSelected);
				MusicToolDeleteBtn.IsEnabled = isEnabled;
				MusicToolExportBtn.IsEnabled = isEnabled;
			});
		}

		private void UpdateAlbumList(List<MusicInfo> music)
		{
			if (music == null)
			{
				Albums = new ObservableCollection<MusicAlbumViewModelV7>();
				return;
			}
			m_bll.GenericAlbumInfo(music).ForEach(delegate(MusicAlbumViewModelV7 n)
			{
				AlbumsOriginal.Add(n);
			});
			IEnumerable<MusicAlbumViewModelV7> enumerable = AlbumsOriginal.Where((MusicAlbumViewModelV7 m) => m.IsInternalPath == (SdCarVm.StorageSelIndex == 0));
			if (AlbumsOriginal.Count > 0)
			{
				if (enumerable.FirstOrDefault() != null)
				{
					enumerable.FirstOrDefault().IsSelected = true;
					enumerable.FirstOrDefault().SingleClickCommand.Execute((object)true);
				}
				Albums = new ObservableCollection<MusicAlbumViewModelV7>(enumerable);
				AllAlbumMusicCount = enumerable.Sum((MusicAlbumViewModelV7 n) => n.FileCount);
			}
			else
			{
				Albums = new ObservableCollection<MusicAlbumViewModelV7>();
				AllAlbumMusicCount = 0;
			}
		}

		public void RefreshAllAlbumMusicSelectedCount()
		{
			int num = 0;
			foreach (MusicAlbumViewModelV7 album in Albums)
			{
				foreach (MusicInfo cachedAllMusic in album.CachedAllMusics)
				{
					if (cachedAllMusic.IsSelected)
					{
						num++;
					}
				}
			}
			AllAlbumMusicSelectedCount = num;
			MusicToolExportBtn.IsEnabled = num > 0;
			MusicToolDeleteBtn.IsEnabled = num > 0;
		}

		public void CheckAllInPagingDataGrid()
		{
			if (FocusedAlbumPaging.CachedAllMusics.Count((MusicInfo m) => m.IsSelected) == 0)
			{
				FocusedAlbumPaging.IsSelectedAllMusics = false;
			}
			else if (FocusedAlbumPaging.CachedAllMusics.Count((MusicInfo m) => !m.IsSelected) == 0)
			{
				FocusedAlbumPaging.IsSelectedAllMusics = true;
			}
			else
			{
				FocusedAlbumPaging.IsSelectedAllMusics = null;
			}
		}

		public void CheckAllInAlbumChecked()
		{
			if (FocusedAlbum.CachedAllMusics.Count((MusicInfo m) => m.IsSelected) == 0)
			{
				FocusedAlbum.IsSelectedAllMusics = false;
			}
			else if (FocusedAlbum.CachedAllMusics.Count((MusicInfo m) => !m.IsSelected) == 0)
			{
				FocusedAlbum.IsSelectedAllMusics = true;
			}
			else
			{
				FocusedAlbum.IsSelectedAllMusics = null;
			}
		}

		public void FocusedAlbumClone()
		{
			HostProxy.CurrentDispatcher.Invoke((Action)delegate
			{
				MusicAlbumViewModelV7 musicAlbumViewModelV = AlbumsOriginal.FirstOrDefault((MusicAlbumViewModelV7 n) => n.IsSelected);
				if (musicAlbumViewModelV != null)
				{
					string text = JsonHelper.SerializeObject2Json((object)musicAlbumViewModelV);
					FocusedAlbumOriginal = JsonHelper.DeserializeJson2Object<MusicAlbumViewModelV7>(text);
				}
			});
		}

		private void OnPageChangedCommand(object prameter)
		{
			RefreshPageControlData(_initData: false);
		}

		public void RefreshPageControlData(bool _initData = true)
		{
			if (_initData)
			{
				CurrentPage = 1;
			}
			Total = FocusedAlbum.CachedAllMusics.Count;
			FocusedAlbumPaging.AlbumID = FocusedAlbum.AlbumID;
			FocusedAlbumPaging.AlbumName = FocusedAlbum.AlbumName;
			FocusedAlbumPaging.AlbumPath1 = FocusedAlbum.AlbumPath1;
			List<MusicInfo> list = FocusedAlbum.CachedAllMusics.Skip((CurrentPage - 1) * PageSize).Take(PageSize).ToList();
			FocusedAlbumPaging.CachedAllMusics = new ObservableCollection<MusicInfo>(list);
			CheckAllInPagingDataGrid();
		}
	}
	public class OnekeyCloneResultViewModel : ViewModelBase
	{
		public OnekeyCloneTransferViewModel _TransferViewModel;

		public ReplayCommand OKCommand { get; }

		public ReplayCommand RetryCommand { get; }

		public OnekeyCloneTransferViewModel TransferViewModel
		{
			get
			{
				return _TransferViewModel;
			}
			set
			{
				_TransferViewModel = value;
				((NotifyBase)this).OnPropertyChanged("TransferViewModel");
			}
		}

		public OnekeyCloneResultViewModel()
		{
			//IL_0013: Unknown result type (might be due to invalid IL or missing references)
			//IL_001d: Expected O, but got Unknown
			//IL_002a: Unknown result type (might be due to invalid IL or missing references)
			//IL_0034: Expected O, but got Unknown
			OKCommand = new ReplayCommand((Action<object>)OKCommandHandler);
			RetryCommand = new ReplayCommand((Action<object>)RetryCommandHandler);
		}

		public override void LoadData(object data)
		{
			TransferViewModel = data as OnekeyCloneTransferViewModel;
			((ViewModelBase)this).LoadData(data);
		}

		private void OKCommandHandler(object data)
		{
			Context.Switch(ViewType.ONEKEYCLONE, null, reload: false, reloadData: true);
		}

		private void RetryCommandHandler(object data)
		{
			if (TransferViewModel.SelectedMasterDevice == null || TransferViewModel.SelectedTargetDevice == null)
			{
				Context.Switch(ViewType.ONEKEYCLONE, null, reload: false, reloadData: true);
				return;
			}
			Context.Switch(ViewType.ONEKEYCLONE_TRANSFER);
			Task.Run(delegate
			{
				TransferViewModel.RetryClone();
			});
		}
	}
