		private async void PicToolDeleteCommandHandler(object parameter)
		{
			List<string> idList = new List<string>();
			foreach (PicAlbumViewModelV7 album in Albums)
			{
				foreach (PicInfoViewModelV7 cachedAllPic in album.CachedAllPics)
				{
					if (cachedAllPic.IsSelected)
					{
						idList.Add(cachedAllPic.RawPicInfo.Id);
					}
				}
			}
			if (idList.Count != 0)
			{
				bool? flag = await MessageWindowHelper.Instance.Show("K0711", ResourcesHelper.StringResources.SingleInstance.PIC_DELETE_CONTENT, "K0327", "K0208", false, (MessageBoxImage)64, (string)null, false, false, false, (Action<IMessageWindowV6>)null, (Predicate<object>)null, (Predicate<object>)null, (Func<bool>)null, (bool?)true, false);
				if (flag.HasValue && flag.Value)
				{
					await bll.DeleteDevicePic(idList);
					PicToolRefreshCommandHandler(null);
				}
			}
		}

		public void PicToolRefreshCommandHandler(object parameter)
		{
			lock (this)
			{
				if (m_LockLoadingData)
				{
					return;
				}
				m_LockLoadingData = true;
			}
			PicToolDeleteBtn.IsEnabled = false;
			PicToolExportBtn.IsEnabled = false;
			try
			{
				Dispatcher currentDispatcher = HostProxy.CurrentDispatcher;
				if (currentDispatcher != null)
				{
					currentDispatcher.Invoke((Action)delegate
					{
						ClearAlbums();
					});
				}
				IsSelectedAllAlbumPic = false;
				SearchText = string.Empty;
				foreach (PicAlbumViewModelV7 album in Albums)
				{
					album.IsSelectedAllPic = false;
				}
				List<PicServerAlbumInfo> picAlbumsViewModel = bll.GetPicAlbumsViewModel();
				LogHelper.LogInstance.Info("Get Albums finished!", false);
				bll.LoadAlbumsInfo(picAlbumsViewModel);
				LogHelper.LogInstance.Info("Load Albums finished!", false);
			}
			catch (Exception arg)
			{
				LogHelper.LogInstance.Debug($"Refresh pictures exception:{arg}", false);
				ReSetPicToolBtnStatus();
			}
			finally
			{
				m_LockLoadingData = false;
			}
		}

		public void SetToolBarEnable()
