		public void ReSetPicToolBtnStatus()
		{
			PicAlbumViewModelV7 focusedAlbum = FocusedAlbum;
			if (focusedAlbum != null)
			{
				ObservableCollection<PicInfoViewModelV7> cachedAllPics = focusedAlbum.CachedAllPics;
				if (cachedAllPics != null && cachedAllPics.FirstOrDefault((PicInfoViewModelV7 m) => m.IsSelected) != null)
				{
					PicToolExportBtn.IsEnabled = true;
					PicToolDeleteBtn.IsEnabled = true;
				}
				else
				{
					PicToolExportBtn.IsEnabled = false;
					PicToolDeleteBtn.IsEnabled = false;
				}
			}
		}

		public void FocusedAlbumClone()
		{
			HostProxy.CurrentDispatcher.Invoke((Action)delegate
			{
				PicAlbumViewModelV7 picAlbumViewModelV = AlbumsOriginal.FirstOrDefault((PicAlbumViewModelV7 n) => n.IsSelected);
				if (picAlbumViewModelV != null)
				{
					string text = JsonHelper.SerializeObject2Json((object)picAlbumViewModelV);
					FocusedAlbumOriginal = JsonHelper.DeserializeJson2Object<PicAlbumViewModelV7>(text);
					foreach (PicInfoListViewModelV7 cachedPic in FocusedAlbumOriginal.CachedPicList)
					{
						foreach (PicInfoViewModelV7 pic in cachedPic.Pics)
						{
							pic.ResetCloneImageUri();
						}
					}
				}
			});
		}

		private void OnPageChangedCommand(object prameter)
		{
			RefreshPageControlData(_initData: false);
		}

		public void RefreshPageControlData(bool _initData = true)
		{
			LogHelper.LogInstance.Debug("Loadding paging data.", false);
			if (_initData)
			{
				CurrentPage = 1;
			}
			Total = FocusedAlbum.CachedAllPics.Count;
			FocusedAlbumPaging.Id = FocusedAlbum.Id;
			FocusedAlbumPaging.AlbumName = FocusedAlbum.AlbumName;
			FocusedAlbumPaging.AlbumPath = FocusedAlbum.AlbumPath;
			FocusedAlbumPaging.DataVersion = FocusedAlbum.DataVersion;
			List<PicInfoViewModelV7> list = FocusedAlbum.CachedAllPics.Skip((CurrentPage - 1) * PageSize).Take(PageSize).ToList();
			FocusedAlbumPaging.CachedAllPics = new ObservableCollection<PicInfoViewModelV7>(list);
			List<PicInfoListViewModelV7> list2 = new List<PicInfoListViewModelV7>();
			foreach (IGrouping<string, PicInfoViewModelV7> item in (from m in list
				group m by m.GroupKey).ToList())
			{
				PicInfoListViewModelV7 picInfoListViewModelV = new PicInfoListViewModelV7
				{
					GroupKey = item.Key
				};
				picInfoListViewModelV.SetSelectionHandler(PicSelectionHandler);
				picInfoListViewModelV.Pics = new ObservableCollection<PicInfoViewModelV7>(item.ToList());
				picInfoListViewModelV.PicCount = picInfoListViewModelV.Pics.Count;
				if (item.Count((PicInfoViewModelV7 m) => m.IsSelected) == 0)
				{
					picInfoListViewModelV.IsListSelected = false;
				}
				else if (item.Count((PicInfoViewModelV7 m) => !m.IsSelected) == 0)
				{
					picInfoListViewModelV.IsListSelected = true;
				}
				else
				{
					picInfoListViewModelV.IsListSelected = null;
				}
				list2.Add(picInfoListViewModelV);
			}
			FocusedAlbumPaging.CachedPicList = new ObservableCollection<PicInfoListViewModelV7>(list2);
			CheckAllInPagingDataGrid();
			ScrollViewer dateGroupScrollViewer = DateGroupScrollViewer;
			if (dateGroupScrollViewer != null)
			{
				dateGroupScrollViewer.ScrollToTop();
			}
			ScrollViewer picNotGroupScrollViewer = PicNotGroupScrollViewer;
			if (picNotGroupScrollViewer != null)
			{
				picNotGroupScrollViewer.ScrollToTop();
			}
			Task.Run(delegate
			{
				LoadPagingPicsThumbnail();
			});
		}

		public void CheckAllInPagingDataGrid()
		{
			if (FocusedAlbumPaging.CachedAllPics.Count((PicInfoViewModelV7 m) => m.IsSelected) == 0)
			{
				FocusedAlbumPaging.IsSelectedAllPic = false;
			}
			else if (FocusedAlbumPaging.CachedAllPics.Count((PicInfoViewModelV7 m) => !m.IsSelected) == 0)
			{
				FocusedAlbumPaging.IsSelectedAllPic = true;
			}
			else
			{
				FocusedAlbumPaging.IsSelectedAllPic = null;
			}
		}

		public void CheckAllInAlbumChecked()
		{
			if (FocusedAlbum.CachedAllPics.Count((PicInfoViewModelV7 m) => m.IsSelected) == 0)
			{
				FocusedAlbum.IsSelectedAllPic = false;
			}
			else if (FocusedAlbum.CachedAllPics.Count((PicInfoViewModelV7 m) => !m.IsSelected) == 0)
			{
				FocusedAlbum.IsSelectedAllPic = true;
			}
			else
			{
				FocusedAlbum.IsSelectedAllPic = null;
			}
		}

		private void LoadPagingPicsThumbnail()
		{
			LogHelper.LogInstance.Debug("Load Picture Thumbnails in Album begin!", false);
			PicInfoListViewModelV7 picInfoListViewModelV = FocusedAlbumPaging.CachedPicList.FirstOrDefault();
			if (picInfoListViewModelV != null)
			{
				AutoResetEvent done = new AutoResetEvent(initialState: false);
				try
				{
					List<PicInfoViewModelV7> pics = FocusedAlbumPaging.CachedAllPics.Where((PicInfoViewModelV7 m) => m.RawPicInfo != null && !m.IsImageLoaded).Take(picInfoListViewModelV.NumberOfVisibleAreaImages).ToList();
					bll.LoadAlbumPicsThumbnail(FocusedAlbum.AlbumPath, pics, delegate
					{
						if (!done.SafeWaitHandle.IsClosed)
						{
							done.Set();
						}
					});
					done.WaitOne(20000);
				}
				finally
				{
					if (done != null)
					{
						((IDisposable)done).Dispose();
					}
				}
			}
			Context.FindViewModel<PicMgtViewModelV7>(typeof(PICMgtViewV7), (string)null).PicListIsLoad = true;
			PicListIsLoad = true;
			LogHelper.LogInstance.Debug("Load Picture Thumbnails in Album finish!", false);
		}
	}
