		private async void ImportVideoCommandHandler(object prameter)
		{
			OpenFileDialog val = new OpenFileDialog();
			((FileDialog)val).Title = "K0496";
			if (HostProxy.LanguageService.IsNeedTranslate())
			{
				((FileDialog)val).Title = HostProxy.LanguageService.Translate("K0496");
			}
			((FileDialog)val).Filter = "Videos|*.mp4;*.rm;*.rmvb;*.avi;*.wmv;";
			val.Multiselect = true;
			((FileDialog)val).FileName = string.Empty;
			((FileDialog)val).FilterIndex = 1;
			if (((CommonDialog)val).ShowDialog() != true)
			{
				return;
			}
			List<string> fileNames = ((FileDialog)val).FileNames.ToList();
			fileNames = await DeviceCommonManagementV6.CheckImportFiles(fileNames);
			if (fileNames.Count == 0)
			{
				return;
			}
			DeviceEx masterDevice = HostProxy.deviceManager.MasterDevice;
			TcpAndroidDevice val2 = (TcpAndroidDevice)(object)((masterDevice is TcpAndroidDevice) ? masterDevice : null);
			if (val2 == null || ((DeviceEx)val2).Property == null)
			{
				return;
			}
			if (new DeviceCommonManagementV6().CheckInternalStorageFreeSize(fileNames))
			{
				await MessageWindowHelper.Instance.Show(string.Empty, "K0366", "K0327", (string)null, false, (MessageBoxImage)48, (string)null, false, false, false, (Action<IMessageWindowV6>)null, (Predicate<object>)null, (Predicate<object>)null, (Func<bool>)null, (bool?)true, false);
				return;
			}
			string text = FocusedAlbum?.AlbumPath;
			if (string.IsNullOrEmpty(text))
			{
				text = Path.Combine(((DeviceEx)val2).Property.InternalStoragePath, "DCIM/Camera");
			}
			string appSaveDir = text;
			if (HostProxy.deviceManager.MasterDevice.ConnectedAppType == "Moto")
			{
				appSaveDir = Path.Combine(((DeviceEx)val2).Property.InternalStoragePath, text, "/");
			}
			await new ImportAndExportWrapper().ImportFile((BusinessType)1410, 20, ResourcesHelper.StringResources.SingleInstance.VIDEO_IMPORT_MESSAGE, "{8BEBE14B-4E45-4D36-8726-8442E6242C01}", BackupRestoreStaticResources.SingleInstance.VIDEO, (Func<List<string>>)(() => fileNames), (Func<string, string>)((string sourcePath) => Path.Combine(appSaveDir, Path.GetFileName(sourcePath))));
			RefreshCommandHandler(null);
		}

