					await new ImportAndExportWrapper().ExportFile((BusinessType)1420, 20, selectedVideoIds, ResourcesHelper.StringResources.SingleInstance.VIDEO_EXPORT_MESSAGE, "{8BEBE14B-4E45-4D36-8726-8442E6242C01}", ResourcesHelper.StringResources.SingleInstance.VIDEO_CONTENT, text, (Func<string, Header, string>)null);
				}
			}
		}

		private async void DeleteVideoCommandHandler(object prameter)
		{
			List<string> _idList = GetSelectedVideoIds(_isRemoveLagerFile: false);
			if (_idList.Count != 0)
			{
				bool? flag = await MessageWindowHelper.Instance.Show(string.Empty, ResourcesHelper.StringResources.SingleInstance.VIDEO_DELETE_CONTENT, "K0327", "K0208", false, (MessageBoxImage)64, (string)null, false, false, false, (Action<IMessageWindowV6>)null, (Predicate<object>)null, (Predicate<object>)null, (Func<bool>)null, (bool?)true, false);
				if (flag.HasValue && flag.Value)
				{
					Stopwatch sw = new Stopwatch();
					Dictionary<string, int> result = new Dictionary<string, int>();
					DeviceEx masterDevice = HostProxy.deviceManager.MasterDevice;
					TcpAndroidDevice val = (TcpAndroidDevice)(object)((masterDevice is TcpAndroidDevice) ? masterDevice : null);
					BusinessData businessData = new BusinessData((BusinessType)1430, (DeviceEx)(object)val, (BusinessStatus)0);
					sw.Start();
					result = (await bllVideo.DeleteDevFilesWithConfirm("deleteVideosById", _idList, result)).Item2;
					sw.Stop();
					HostProxy.BehaviorService.Collect((BusinessType)1430, businessData.Update(sw.ElapsedMilliseconds, (BusinessStatus)((result["success"] > 0) ? 10 : 20), (object)result));
					RefreshCommandHandler(null);
