		public async void RefreshCommandHandler(object prameter)
		{
			if (prameter != null)
			{
				((TextBox)((prameter is TextBox) ? prameter : null)).Text = string.Empty;
			}
			VideoToolExportBtn.IsEnabled = false;
			VideoToolDeleteBtn.IsEnabled = false;
			IsSelectedAllAlbumVideo = false;
			AlbumList.Clear();
			await AsyncDataLoader.Loading((Action)delegate
			{
				try
				{
					if (!bllVideo.GetVideoCount(out var _, out var _))
					{
						MessageWindowHelper.Instance.Show("K0668", "Maybe your storage space is insufficient, please check", "K0327", (string)null, false, (MessageBoxImage)64, (string)null, false, false, false, (Action<IMessageWindowV6>)null, (Predicate<object>)null, (Predicate<object>)null, (Func<bool>)null, (bool?)true, false);
					}
					else
					{
						List<ServerAlbumInfo> albums = bllVideo.GetAlbums();
						GetVideoList(albums);
						Thread.Sleep(500);
					}
				}
				catch
				{
					MessageWindowHelper.Instance.Show("K0668", "Maybe your storage space is insufficient, please check", "K0327", (string)null, false, (MessageBoxImage)64, (string)null, false, false, false, (Action<IMessageWindowV6>)null, (Predicate<object>)null, (Predicate<object>)null, (Func<bool>)null, (bool?)true, false);
				}
			});
		}

		private void GetVideoList(List<ServerAlbumInfo> albums)
		{
			List<Video> videos = bllVideo.GetVideos(albums);
			Dispatcher currentDispatcher = HostProxy.CurrentDispatcher;
			if (currentDispatcher == null)
			{
				return;
			}
			currentDispatcher.Invoke((Action)delegate
			{
				AlbumList.Clear();
				AlbumsOriginal.Clear();
				FocusedAlbum.CachedAllVideos.Clear();
				FocusedAlbum.IsSelectedAllVideo = false;
				FocusedAlbumPaging.CachedAllVideos.Clear();
				FocusedAlbumPaging.CacheVideoGroupList.Clear();
				FocusedAlbumPaging.IsSelectedAllVideo = false;
				Total = 0;
				CurrentPage = 1;
				int num = 0;
				foreach (ServerAlbumInfo album in albums)
				{
					VideoAlbumViewModelV7 videoAlbumViewModelV = new VideoAlbumViewModelV7
					{
						RawAlbumInfo = album
					};
					if (videoAlbumViewModelV.IsInternalPath == IsSelectedInternal)
					{
						num += videoAlbumViewModelV.FileCount;
						AlbumsOriginal.Add(videoAlbumViewModelV);
					}
				}
				AllAlbumVideoCount = num;
				AllAlbumVideoSelectedCount = 0;
				foreach (Video video in videos.OrderByDescending((Video n) => n.ModifiyDate).ToList())
				{
					VideoInfoViewModelV7 videoInfoViewModelV = new VideoInfoViewModelV7();
					videoInfoViewModelV.RawVideoInfo = new VideoInfo();
					videoInfoViewModelV.RawVideoInfo.SetData(video, albums.SingleOrDefault((ServerAlbumInfo a) => a.AlbumPath == video.Album));
					videoInfoViewModelV.SetGroupKey();
					AlbumsOriginal.SingleOrDefault((VideoAlbumViewModelV7 a) => a.AlbumPath == video.Album)?.CachedAllVideos.Add(videoInfoViewModelV);
				}
				foreach (VideoAlbumViewModelV7 item in AlbumsOriginal)
				{
					item.ResetVideoGroupList();
				}
				if (AlbumsOriginal.Count > 0)
				{
					IEnumerable<VideoAlbumViewModelV7> enumerable = AlbumsOriginal.Where((VideoAlbumViewModelV7 m) => m.IsInternalPath == IsSelectedInternal);
					if (enumerable.FirstOrDefault() != null)
					{
						enumerable.FirstOrDefault().IsSelected = true;
						enumerable.FirstOrDefault().SingleClickCommand.Execute((object)true);
					}
					AlbumList = new ObservableCollection<VideoAlbumViewModelV7>(enumerable);
				}
				else
				{
					AlbumList = new ObservableCollection<VideoAlbumViewModelV7>();
				}
			});
		}

		private void SearchCommandHandler(object prameter)
		{
			if (prameter == null)
			{
				return;
			}
			foreach (VideoInfoViewModelV7 _single in FocusedAlbum.CachedAllVideos)
			{
				FocusedAlbumOriginal.CachedAllVideos.First((VideoInfoViewModelV7 m) => m.RawVideoInfo.RawVideo.Id == _single.RawVideoInfo.RawVideo.Id).IsSelected = _single.IsSelected;
			}
			foreach (VideoInfoGroupViewModelV7 _single2 in FocusedAlbum.CacheVideoGroupList)
			{
				foreach (VideoInfoViewModelV7 _singleChild in _single2.Videos)
				{
					FocusedAlbumOriginal.CacheVideoGroupList.First((VideoInfoGroupViewModelV7 m) => m.GroupKey == _single2.GroupKey).Videos.First((VideoInfoViewModelV7 m) => m.RawVideoInfo.RawVideo.Id == _singleChild.RawVideoInfo.RawVideo.Id).IsSelected = _singleChild.IsSelected;
				}
			}
			string searchText = prameter.ToString().ToLower();
			FocusedAlbum.CachedAllVideos = new ObservableCollection<VideoInfoViewModelV7>(FocusedAlbumOriginal.CachedAllVideos.Where((VideoInfoViewModelV7 m) => m.VideoName.ToLower().Contains(searchText)));
			new ObservableCollection<VideoInfoGroupViewModelV7>();
			for (int num = 0; num < FocusedAlbumOriginal.CacheVideoGroupList.Count; num++)
			{
				IEnumerable<VideoInfoViewModelV7> collection = FocusedAlbumOriginal.CacheVideoGroupList[num].Videos.Where((VideoInfoViewModelV7 m) => m.VideoName.ToLower().Contains(searchText));
				FocusedAlbum.CacheVideoGroupList[num].SetVideos(new ObservableCollection<VideoInfoViewModelV7>(collection));
			}
			RefreshPageControlData();
		}

		private List<string> GetSelectedVideoIds(bool _isRemoveLagerFile = true)
		{
			List<string> list = new List<string>();
			Dictionary<string, long> dictionary = new Dictionary<string, long>();
			foreach (VideoAlbumViewModelV7 album in AlbumList)
			{
				foreach (VideoInfoViewModelV7 cachedAllVideo in album.CachedAllVideos)
				{
					if (cachedAllVideo.IsSelected)
					{
						if (cachedAllVideo.Size > 4294967296L && _isRemoveLagerFile)
						{
							dictionary.Add(cachedAllVideo.RawVideoInfo.FilePath, cachedAllVideo.Size);
						}
						else
						{
							list.Add(cachedAllVideo.RawVideoInfo.RawVideo.Id.ToString());
						}
					}
				}
			}
			DeviceCommonManagementV6.CheckExportFiles(dictionary);
			return list;
		}

		public override void Reset()
		{
			Dispatcher currentDispatcher = HostProxy.CurrentDispatcher;
			if (currentDispatcher == null)
			{
				return;
			}
			currentDispatcher.Invoke((Action)delegate
			{
				((ViewModelBase)this).Reset();
				if (((ViewModelBase)this).DataIsLoaded)
				{
					AlbumList.Clear();
					FocusedAlbumPaging.CachedAllVideos.Clear();
					FocusedAlbumPaging.CacheVideoGroupList.Clear();
					FocusedAlbumPaging.IsSelectedAllVideo = false;
				}
				Total = 0;
				CurrentPage = 1;
			});
		}

		public void RefreshAllAlbumPicSelectedCount()
		{
			int num = 0;
			foreach (VideoAlbumViewModelV7 album in AlbumList)
			{
				foreach (VideoInfoViewModelV7 cachedAllVideo in album.CachedAllVideos)
				{
					if (cachedAllVideo.IsSelected)
					{
						num++;
					}
				}
			}
			VideoToolExportBtn.IsEnabled = num > 0;
			VideoToolDeleteBtn.IsEnabled = num > 0;
			AllAlbumVideoSelectedCount = num;
		}

		public void FocusedAlbumClone()
		{
			HostProxy.CurrentDispatcher.Invoke((Action)delegate
			{
				VideoAlbumViewModelV7 videoAlbumViewModelV = AlbumsOriginal.FirstOrDefault((VideoAlbumViewModelV7 n) => n.IsSelected);
				if (videoAlbumViewModelV != null)
				{
					string text = JsonHelper.SerializeObject2Json((object)videoAlbumViewModelV);
					FocusedAlbumOriginal = JsonHelper.DeserializeJson2Object<VideoAlbumViewModelV7>(text);
					foreach (VideoInfoGroupViewModelV7 cacheVideoGroup in FocusedAlbumOriginal.CacheVideoGroupList)
					{
						foreach (VideoInfoViewModelV7 video in cacheVideoGroup.Videos)
						{
							video.ResetCloneImageUri();
						}
					}
				}
			});
		}

		private void OnPageChangedCommand(object prameter)
		{
			RefreshPageControlData(_initData: false);
		}

		public void RefreshPageControlData(bool _initData = true)
		{
			LogHelper.LogInstance.Debug("Loadding paging data.", false);
			if (_initData)
			{
				CurrentPage = 1;
			}
			Total = FocusedAlbum.CachedAllVideos.Count;
			FocusedAlbumPaging.RawAlbumInfo = FocusedAlbum.RawAlbumInfo;
			List<VideoInfoViewModelV7> list = FocusedAlbum.CachedAllVideos.Skip((CurrentPage - 1) * PageSize).Take(PageSize).ToList();
			FocusedAlbumPaging.CachedAllVideos = new ObservableCollection<VideoInfoViewModelV7>(list);
			List<VideoInfoGroupViewModelV7> list2 = new List<VideoInfoGroupViewModelV7>();
			foreach (IGrouping<string, VideoInfoViewModelV7> item in (from m in list
				group m by m.GroupKey).ToList())
			{
				VideoInfoGroupViewModelV7 videoInfoGroupViewModelV = new VideoInfoGroupViewModelV7
				{
					GroupKey = item.Key
				};
				videoInfoGroupViewModelV.Videos = new ObservableCollection<VideoInfoViewModelV7>(item.ToList());
				videoInfoGroupViewModelV.VideoCount = videoInfoGroupViewModelV.Videos.Count;
				if (item.Count((VideoInfoViewModelV7 m) => m.IsSelected) == 0)
				{
					videoInfoGroupViewModelV.IsGroupSelected = false;
				}
				else if (item.Count((VideoInfoViewModelV7 m) => !m.IsSelected) == 0)
				{
					videoInfoGroupViewModelV.IsGroupSelected = true;
				}
				else
				{
					videoInfoGroupViewModelV.IsGroupSelected = null;
				}
				list2.Add(videoInfoGroupViewModelV);
			}
			FocusedAlbumPaging.CacheVideoGroupList = new ObservableCollection<VideoInfoGroupViewModelV7>(list2);
			CheckAllInPagingDataGrid();
			ScrollViewer dateGroupScrollViewer = DateGroupScrollViewer;
			if (dateGroupScrollViewer != null)
			{
				dateGroupScrollViewer.ScrollToTop();
			}
			ScrollViewer picNotGroupScrollViewer = PicNotGroupScrollViewer;
			if (picNotGroupScrollViewer != null)
			{
				picNotGroupScrollViewer.ScrollToTop();
			}
			Task.Run(delegate
			{
				if (HostProxy.deviceManager.MasterDevice.ConnectedAppType == "Ma" && HostProxy.deviceManager.MasterDevice.AppVersion >= 4311)
				{
					UpdateVideoImages();
				}
				else if (HostProxy.deviceManager.MasterDevice.ConnectedAppType == "Moto" && HostProxy.deviceManager.MasterDevice.AppVersion >= 1300507)
				{
					UpdateVideoImages();
				}
				else
				{
					UpdateVideoImages_old();
				}
			});
		}

		public void CheckAllInPagingDataGrid()
		{
			if (FocusedAlbumPaging.CachedAllVideos.Count((VideoInfoViewModelV7 m) => m.IsSelected) == 0)
			{
				FocusedAlbumPaging.IsSelectedAllVideo = false;
			}
			else if (FocusedAlbumPaging.CachedAllVideos.Count((VideoInfoViewModelV7 m) => !m.IsSelected) == 0)
			{
				FocusedAlbumPaging.IsSelectedAllVideo = true;
			}
			else
			{
				FocusedAlbumPaging.IsSelectedAllVideo = null;
			}
		}

		public void CheckAllInAlbumChecked()
		{
			if (FocusedAlbum.CachedAllVideos.Count((VideoInfoViewModelV7 m) => m.IsSelected) == 0)
			{
				FocusedAlbum.IsSelectedAllVideo = false;
			}
			else if (FocusedAlbum.CachedAllVideos.Count((VideoInfoViewModelV7 m) => !m.IsSelected) == 0)
			{
				FocusedAlbum.IsSelectedAllVideo = true;
			}
			else
			{
				FocusedAlbum.IsSelectedAllVideo = null;
			}
		}

		private void UpdateVideoImages_old()
		{
			try
			{
				string videoCacheDir = Configurations.VideoCacheDir;
				new List<ServerAlbumInfo>();
				bllVideo.ExportVideoThumbnails_old(FocusedAlbumPaging, videoCacheDir, delegate(VideoThumbnails video, bool res)
				{
					if (res)
					{
						Dispatcher currentDispatcher = HostProxy.CurrentDispatcher;
						if (currentDispatcher != null)
						{
							currentDispatcher.Invoke((Action)delegate
							{
								VideoAlbumViewModelV7 videoAlbumViewModelV = AlbumsOriginal.FirstOrDefault((VideoAlbumViewModelV7 a) => a.AlbumPath == FocusedAlbumPaging.AlbumPath);
								if (videoAlbumViewModelV != null)
								{
									VideoInfoViewModelV7 videoInfoViewModelV = videoAlbumViewModelV.CachedAllVideos.FirstOrDefault((VideoInfoViewModelV7 v) => v.RawVideoInfo.RawVideo.Name == video.Name);
									if (videoInfoViewModelV != null)
									{
										videoInfoViewModelV.RawVideoInfo.LocalVideoImagePath = video.LocalFilePath;
										videoInfoViewModelV.VideoImage = (ImageSource)(object)ImageHandleHelper.LoadBitmap(video.LocalFilePath);
										FocusedAlbumClone();
										LogHelper.LogInstance.Debug("albumVM.VideoImage:" + ((object)videoInfoViewModelV.VideoImage).ToString(), false);
									}
								}
							});
						}
					}
				});
			}
			catch (Exception ex)
			{
				LogHelper.LogInstance.Error("Export video image throw exception:" + ex.ToString(), false);
			}
		}

		private void UpdateVideoImages()
		{
			try
			{
				string videoCacheDir = Configurations.VideoCacheDir;
				foreach (List<int> item in (from x in FocusedAlbumPaging.CachedAllVideos.Select((VideoInfoViewModelV7 num, int index) => new
					{
						num.RawVideoInfo.RawVideo.Id,
						index
					})
					group x by x.index / 10 into g
					select g.Select(x => x.Id).ToList()).ToList())
				{
					bllVideo.ExportVideoThumbnails(item, videoCacheDir, delegate(VideoThumbnails video, bool res)
					{
						if (res)
						{
							Dispatcher currentDispatcher2 = HostProxy.CurrentDispatcher;
							if (currentDispatcher2 != null)
							{
								currentDispatcher2.Invoke((Action)delegate
								{
									VideoAlbumViewModelV7 videoAlbumViewModelV = AlbumsOriginal.FirstOrDefault((VideoAlbumViewModelV7 a) => a.AlbumPath == FocusedAlbumPaging.AlbumPath);
									if (videoAlbumViewModelV != null)
									{
										VideoInfoViewModelV7 videoInfoViewModelV = videoAlbumViewModelV.CachedAllVideos.FirstOrDefault((VideoInfoViewModelV7 v) => v.RawVideoInfo.RawVideo.Name == video.Name);
										if (videoInfoViewModelV != null)
										{
											videoInfoViewModelV.RawVideoInfo.LocalVideoImagePath = video.LocalFilePath;
											videoInfoViewModelV.VideoImage = (ImageSource)(object)ImageHandleHelper.LoadBitmap(video.LocalFilePath);
											LogHelper.LogInstance.Debug("albumVM.VideoImage:" + ((object)videoInfoViewModelV.VideoImage).ToString(), false);
										}
									}
								});
							}
						}
					});
				}
				Dispatcher currentDispatcher = HostProxy.CurrentDispatcher;
				if (currentDispatcher != null)
				{
					currentDispatcher.Invoke((Action)delegate
					{
						FocusedAlbumClone();
					});
				}
			}
			catch (Exception ex)
			{
				LogHelper.LogInstance.Error("Export video image throw exception:" + ex.ToString(), false);
			}
		}
	}
