		public string Screencap()
		{
			DeviceEx masterDevice = HostProxy.deviceManager.MasterDevice;
			TcpAndroidDevice val = (TcpAndroidDevice)(object)((masterDevice is TcpAndroidDevice) ? masterDevice : null);
			string screencapDir = Configurations.ScreencapDir;
			if (!Directory.Exists(screencapDir))
			{
				try
				{
					Directory.CreateDirectory(screencapDir);
				}
				catch (Exception ex)
				{
					LogHelper.LogInstance.Error($"Create new dir{screencapDir} throw exception:{ex.ToString()}", false);
					return string.Empty;
				}
			}
			if (((DeviceEx)val).Property == null)
			{
				return string.Empty;
			}
			string internalStoragePath = ((DeviceEx)val).Property.InternalStoragePath;
			internalStoragePath = ((!string.IsNullOrEmpty(internalStoragePath) && internalStoragePath.Length != 0 && internalStoragePath[0] == '/') ? internalStoragePath.TrimEnd(new char[1] { '/' }) : "/storage/emulated/0");
			string arg = $"{internalStoragePath}/screencap_lmsa.lmsapng";
			string text = Path.Combine(screencapDir, "screencap_lmsa_" + Guid.NewGuid().ToString("N") + ".png");
			if (File.Exists(text))
			{
				try
				{
					File.Delete(text);
				}
				catch
				{
				}
			}
			string arg2 = ((DeviceEx)val).DeviceOperator.Shell(((DeviceEx)val).Identifer, $"screencap -p {arg}");
			LogHelper.LogInstance.Info($"Screen cap response {arg2}", false);
			string arg3 = ((DeviceEx)val).DeviceOperator.Command($"pull {arg} {text}", -1, ((DeviceEx)val).Identifer);
			LogHelper.LogInstance.Info($"Screen cap pull file response {arg3}", false);
			return text;
		}

