		private async void DeleteVideoCommandHandler(object prameter)
		{
			if (OnDeleteEvent != null)
			{
				OnDeleteEvent();
			}
			List<Video> vedios = GetSelectedVideos();
			if (vedios.Count < 1 || !MessageBoxHelper.DeleteConfirmMessagebox(ResourcesHelper.StringResources.SingleInstance.CONTACT_DELETE_TITLE, ResourcesHelper.StringResources.SingleInstance.VIDEO_DELETE_CONTENT))
			{
				return;
			}
			BusinessData businessData = new BusinessData((BusinessType)1430, Context.CurrentDevice, (BusinessStatus)0);
			List<string> idArr = vedios.Select((Video p) => $"{p.Id}").ToList();
			await AsyncDataLoader.Loading((Action)delegate
			{
				Stopwatch stopwatch = new Stopwatch();
				Dictionary<string, int> result = new Dictionary<string, int>();
				stopwatch.Start();
				Tuple<bool, Dictionary<string, int>> result2 = VideoManager.DeleteDevFilesWithConfirm("deleteVideosById", idArr, result).Result;
				bool item = result2.Item1;
				result = result2.Item2;
				stopwatch.Stop();
				HostProxy.BehaviorService.Collect((BusinessType)1430, businessData.Update(stopwatch.ElapsedMilliseconds, (BusinessStatus)10, (object)result));
				if (item)
				{
					Dispatcher currentDispatcher = HostProxy.CurrentDispatcher;
					if (currentDispatcher != null)
					{
						currentDispatcher.Invoke((Action)delegate
						{
							foreach (Video item2 in vedios)
							{
								VideoInfoViewModel video = VideoList.Where((VideoInfoViewModel v) => v.RawVideoInfo.RawVideo.Id == item2.Id).FirstOrDefault();
								if (video != null)
								{
									VideoList.Remove(video);
									int videoCount = VideoCount;
									VideoCount = videoCount - 1;
									VideoAlbumViewModel videoAlbumViewModel = AlbumList.Where((VideoAlbumViewModel a) => a.AlbumName == video.RawVideoInfo.AlbumName).FirstOrDefault();
									if (videoAlbumViewModel != null)
									{
										videoAlbumViewModel.VideoInfoList.Remove(video);
										videoAlbumViewModel.FileCount--;
									}
								}
							}
							foreach (VideoAlbumViewModel item3 in AlbumList.Where((VideoAlbumViewModel a) => a.VideoInfoList.Count == 0).ToList())
							{
								AlbumList.Remove(item3);
								int videoCount = AlbumCount;
								AlbumCount = videoCount - 1;
							}
							IsAllSelected = false;
							OnDeleteEvent?.Invoke();
						});
					}
				}
			});
		}

		private void RefreshCommandHandler(object prameter)
		{
			if (prameter != null)
			{
				((TextBox)((prameter is TextBox) ? prameter : null)).Text = string.Empty;
			}
			AsyncDataLoader.BeginLoading((Func<Tuple<bool, string, string>>)delegate
			{
				try
				{
					if (!VideoManager.GetVideoCount(out var videoCnt, out var albumCnt))
					{
						return new Tuple<bool, string, string>(item1: false, "K0668", "Maybe your storage space is insufficient, please check");
					}
					List<ServerAlbumInfo> albums = VideoManager.GetAlbums();
					GetVideoList(albums, videoCnt, albumCnt);
					VideosTotalSize = GlobalFun.ConvertLong2String(VideoList.Sum((VideoInfoViewModel n) => n.Size), "F2", true);
					VideosChoosed = 0;
					AlbumChoosed = 0;
					VideosChoosedInSelectAlbum = 0;
					Task.Factory.StartNew(delegate
					{
						UpdateVideoImages(albums);
					});
					Dispatcher currentDispatcher = HostProxy.CurrentDispatcher;
					if (currentDispatcher != null)
					{
						currentDispatcher.Invoke((Action)delegate
						{
							if (MainView == VideoViewType.Album)
							{
								bool flag = false;
								if (AlbumList != null && SelectedAlbum != null && AlbumView == VideoViewType.Video)
								{
									flag = AlbumList.Count((VideoAlbumViewModel n) => n.AlbumName == SelectedAlbum.AlbumName) != 0;
								}
								if (!flag)
								{
									AlbumViewCallback?.Invoke(VideoViewType.Album);
								}
								else
								{
									UpdateAlbumVideoList();
								}
							}
							IsAllSelected = false;
						});
					}
				}
				catch
				{
					return new Tuple<bool, string, string>(item1: false, "K0668", "Maybe your storage space is insufficient, please check");
				}
				return (Tuple<bool, string, string>)null;
			}, (ILoading)(object)ViewContext.SingleInstance.MainViewModel, (Action<object>)null);
		}

