			{
				e.Current.SoftStatusChanged += E_SoftStatusChanged;
			}
			if (e.Previous != null && (int)e.Previous.ConnectType != 4)
			{
				e.Previous.SoftStatusChanged -= E_SoftStatusChanged;
			}
