			{
				for (int num = ConnectedDevices.Count - 1; num >= 0; num--)
				{
					if (ConnectedDevices[num].Key.Equals(e.Identifer))
					{
						ConnectedDevices.RemoveAt(num);
					}
				}
			});
		}

