						Icon = (ImageSource)Application.Current.FindResource((object)"bottom_usbDrawingImage");
						HoverIcon = (ImageSource)Application.Current.FindResource((object)"bottom_usbDrawingImage_ffffff");
					}
					else if ((int)device.ConnectType == 4)
					{
						Icon = (ImageSource)Application.Current.FindResource((object)"connected_wifiDrawingImage");
						HoverIcon = (ImageSource)Application.Current.FindResource((object)"connected_wifiDrawingImage_ffffff");
					}
				}
			}
