		private void OnWifiMonitoringEndPointChanged(List<Tuple<string, string>> ipGateWayArr)
		{
			if (ipGateWayArr == null)
			{
				return;
			}
			List<JsonEndPoint> EPs = new List<JsonEndPoint>(ipGateWayArr.Count);
			foreach (Tuple<string, string> item in ipGateWayArr)
			{
				string[] array = item.Item1.Split(new char[1] { ':' }, StringSplitOptions.RemoveEmptyEntries);
				if (array.Count() >= 2)
				{
					EPs.Add(new JsonEndPoint(array[0], int.Parse(array[1])));
				}
			}
			try
			{
				Dispatcher currentDispatcher = HostProxy.CurrentDispatcher;
				if (currentDispatcher == null)
				{
					return;
				}
				currentDispatcher.BeginInvoke((Delegate)(Action)delegate
				{
					//IL_0018: Unknown result type (might be due to invalid IL or missing references)
					//IL_001e: Expected O, but got Unknown
					string text = JsonHelper.SerializeObject2Json((object)new JsonEndPoints(EPs));
					MemoryStream memoryStream = QrCodeUtility.GenerateQrCodeImageStream(text);
					BitmapImage val = new BitmapImage();
					val.BeginInit();
					val.StreamSource = new MemoryStream(memoryStream.ToArray());
					val.EndInit();
					try
					{
						QrImageSource = (ImageSource)(object)val;
						IPAddressInfo = text;
					}
					catch (Exception)
					{
					}
				}, Array.Empty<object>());
			}
			catch (Exception)
			{
			}
		}

