		}

		private void SearchCommandHandler(object args)
		{
			if (SelectedNode != null && IsSearching)
			{
				IsSearching = false;
				SearchKeywords = string.Empty;
				Refresh(SelectedNode);
			}
			else
			{
				Search(SelectedNode, SearchKeywords);
			}
		}
