	public class PCFolderTreeViewModel : FolderTreeViewModel
	{
		public Action<FolderFileViewModel> SelectionHandler { get; private set; }

		public PCFolderTreeViewModel(Action<FolderFileViewModel> selectionHandler)
		{
			SelectionHandler = selectionHandler;
		}

		private FolderFileViewModel GetFavoriteDir()
		{
			try
			{
				string folderPath = Environment.GetFolderPath(Environment.SpecialFolder.Favorites);
				FolderFileViewModel folderFileViewModel = new FolderFileViewModel(isFolder: true);
				new DirectoryInfo(folderPath);
				folderFileViewModel.Parent = null;
				folderFileViewModel.IsExpanded = false;
				folderFileViewModel.IsSelected = false;
				folderFileViewModel.Path = folderPath;
				return folderFileViewModel;
			}
			catch (Exception ex)
			{
				LogHelper.LogInstance.Error("Get favorites folder throw exception:" + ex.ToString(), false);
				return null;
			}
		}

		public override List<FolderFileViewModel> GetRootDirectories()
		{
			try
			{
				List<FolderFileViewModel> list = new List<FolderFileViewModel>();
				string[] logicalDrives = Directory.GetLogicalDrives();
				foreach (string text in logicalDrives)
				{
					FolderFileViewModel folderFileViewModel = new FolderFileViewModel(isFolder: true);
					string upperName = (folderFileViewModel.DisplayName = text.Trim(new char[1] { Path.DirectorySeparatorChar }));
					folderFileViewModel.UpperName = upperName;
					folderFileViewModel.Parent = null;
					folderFileViewModel.IsExpanded = false;
					folderFileViewModel.IsSelected = false;
					folderFileViewModel.Path = text;
					list.Add(folderFileViewModel);
				}
				FolderFileViewModel favoriteDir = GetFavoriteDir();
				if (favoriteDir != null)
				{
					list.Add(favoriteDir);
				}
				return list;
			}
			catch (Exception ex)
			{
				LogHelper.LogInstance.Error("Get root dir throw exception:" + ex.ToString(), false);
			}
			return null;
		}

		protected override List<FolderFileViewModel> DoGetChildNodes(FolderFileViewModel node)
		{
			string empty = string.Empty;
			if (node == null || string.IsNullOrEmpty(empty = node.Path))
			{
				return null;
			}
			if (!Directory.Exists(empty))
			{
				return null;
			}
			try
			{
				IOrderedEnumerable<string> orderedEnumerable = from m in Directory.GetDirectories(empty)
					orderby m
					select m;
				List<FolderFileViewModel> list = new List<FolderFileViewModel>();
				foreach (string item in orderedEnumerable)
				{
					DirectoryInfo directoryInfo = new DirectoryInfo(item);
					if (directoryInfo.Exists)
					{
						FolderFileViewModel folderFileViewModel = new FolderFileViewModel(isFolder: true);
						folderFileViewModel.IsExpanded = false;
						folderFileViewModel.IsSelected = false;
						folderFileViewModel.Path = item;
						folderFileViewModel.FileSize = 0L;
						folderFileViewModel.UpdateDate = directoryInfo.LastWriteTime;
						folderFileViewModel.FileType = "File folder";
						list.Add(folderFileViewModel);
					}
				}
				foreach (string item2 in from m in Directory.GetFiles(empty)
					orderby m
					select m)
				{
					System.IO.FileInfo fileInfo = new System.IO.FileInfo(item2);
					if (fileInfo.Exists)
					{
						FolderFileViewModel folderFileViewModel2 = new FolderFileViewModel(isFolder: false);
						folderFileViewModel2.IsExpanded = false;
						folderFileViewModel2.IsSelected = false;
						folderFileViewModel2.Path = item2;
						folderFileViewModel2.FileSize = fileInfo.Length;
						folderFileViewModel2.UpdateDate = fileInfo.LastWriteTime;
						string extension = fileInfo.Extension;
						if (!string.IsNullOrEmpty(extension))
						{
							folderFileViewModel2.FileType = $"{extension.ToUpper().TrimStart(new char[1] { '.' })} file";
						}
						list.Add(folderFileViewModel2);
					}
				}
				return list;
			}
			catch (Exception ex)
			{
				LogHelper.LogInstance.Error($"Get [{empty}]sub dir throw exception:{ex.ToString()}", false);
			}
			return null;
		}

		protected override void OnSelectedChanged(FolderFileViewModel item, bool prevSelected)
		{
			base.OnSelectedChanged(item, prevSelected);
			SelectionHandler?.Invoke(item);
		}

		public override char GetDirectorySeparatorChar()
		{
			return Path.DirectorySeparatorChar;
		}

		protected override void DoSearch(FolderFileViewModel node, string keywords, CancellationTokenSource cancellationTokenSource, Action<FolderFileViewModel> itemFoundCallback)
		{
			DirectoryInfo directoryInfo = new DirectoryInfo(base.SelectedNode.Path);
			if (!directoryInfo.Exists)
			{
				return;
			}
			string value = keywords.ToUpper();
			Queue<DirectoryInfo> queue = new Queue<DirectoryInfo>();
			queue.Enqueue(directoryInfo);
			while (queue.Count != 0)
			{
				DirectoryInfo directoryInfo2 = queue.Dequeue();
				try
				{
					DirectoryInfo[] directories = directoryInfo2.GetDirectories();
					foreach (DirectoryInfo directoryInfo3 in directories)
					{
						if (directoryInfo3.Name.ToUpper().Contains(value))
						{
							FolderFileViewModel folderFileViewModel = new FolderFileViewModel(isFolder: true);
							folderFileViewModel.IsExpanded = false;
							folderFileViewModel.IsSelected = false;
							folderFileViewModel.Path = directoryInfo3.FullName;
							folderFileViewModel.FileSize = 0L;
							folderFileViewModel.UpdateDate = directoryInfo3.LastWriteTime;
							folderFileViewModel.FileType = "File folder";
							itemFoundCallback?.Invoke(folderFileViewModel);
						}
						queue.Enqueue(directoryInfo3);
					}
					System.IO.FileInfo[] files = directoryInfo2.GetFiles();
					foreach (System.IO.FileInfo fileInfo in files)
					{
						if (fileInfo.Name.ToUpper().Contains(value))
						{
							FolderFileViewModel folderFileViewModel2 = new FolderFileViewModel(isFolder: false);
							folderFileViewModel2.IsExpanded = false;
							folderFileViewModel2.IsSelected = false;
							folderFileViewModel2.Path = fileInfo.FullName;
							folderFileViewModel2.FileSize = fileInfo.Length;
							folderFileViewModel2.UpdateDate = fileInfo.LastWriteTime;
							string extension = fileInfo.Extension;
							if (!string.IsNullOrEmpty(extension))
							{
								folderFileViewModel2.FileType = $"{extension.ToUpper().TrimStart(new char[1] { '.' })} file";
							}
							itemFoundCallback?.Invoke(folderFileViewModel2);
						}
					}
				}
				catch (Exception arg)
				{
					LogHelper.LogInstance.Error($"PCFolderTreeViewModel.DoSearch failed, will skip this directory{directoryInfo2?.FullName}, exception:{arg}", false);
				}
			}
		}
	}
	public class PhoneFolderTreeViewModel : FolderTreeViewModel
	{
		private DeviceFileSystemManager _deviceFileSystemManager;

		public Action<FolderFileViewModel> SelectionHandler { get; private set; }

		public bool InternalStroageFocused
		{
			get
			{
				if (base.SelectedNode == null)
				{
					return true;
				}
				_ = string.Empty;
				FolderFileViewModel parent = base.SelectedNode;
				while (parent.Parent != null)
				{
					parent = parent.Parent;
				}
				return parent.UpperName == "INTERNAL_STORAGE";
			}
		}

		public PhoneFolderTreeViewModel(Action<FolderFileViewModel> selectionHandler)
		{
			SelectionHandler = selectionHandler;
			_deviceFileSystemManager = new DeviceFileSystemManager();
		}

		protected override List<FolderFileViewModel> DoGetChildNodes(FolderFileViewModel node)
		{
			string empty = string.Empty;
			if (node == null || string.IsNullOrEmpty(empty = node.Path))
			{
				return null;
			}
			List<lenovo.mbg.service.lmsa.phoneManager.Model.FileInfo> filesInfo = _deviceFileSystemManager.GetFilesInfo(empty);
			return createFolderFileViewModel(filesInfo);
		}

		private List<FolderFileViewModel> createFolderFileViewModel(List<lenovo.mbg.service.lmsa.phoneManager.Model.FileInfo> files)
		{
			if (files == null || files.Count == 0)
			{
				return null;
			}
			List<FolderFileViewModel> list = new List<FolderFileViewModel>();
			foreach (lenovo.mbg.service.lmsa.phoneManager.Model.FileInfo item in from m in files
				where m.BooleanIsFolder
				orderby m.RawFileName
				select m)
			{
				FolderFileViewModel folderFileViewModel = new FolderFileViewModel(isFolder: true);
				folderFileViewModel.IsExpanded = false;
				folderFileViewModel.IsSelected = false;
				folderFileViewModel.Path = item.RawFilePath;
				folderFileViewModel.DisplayName = item.RawFileName;
				folderFileViewModel.UpperName = item.RawFileName;
				folderFileViewModel.FileSize = item.LongFileSize;
				folderFileViewModel.UpdateDate = item.DateTimeModifiedDate;
				folderFileViewModel.FileType = item.RawFileType;
				list.Add(folderFileViewModel);
			}
			foreach (lenovo.mbg.service.lmsa.phoneManager.Model.FileInfo item2 in from m in files
				where !m.BooleanIsFolder
				orderby m.RawFileName
				select m)
			{
				FolderFileViewModel folderFileViewModel2 = new FolderFileViewModel(isFolder: false);
				folderFileViewModel2.IsExpanded = false;
				folderFileViewModel2.IsSelected = false;
				folderFileViewModel2.Path = item2.RawFilePath;
				folderFileViewModel2.DisplayName = item2.RawFileName;
				folderFileViewModel2.UpperName = item2.RawFileName;
				folderFileViewModel2.FileSize = item2.LongFileSize;
				folderFileViewModel2.UpdateDate = item2.DateTimeModifiedDate;
				folderFileViewModel2.FileType = item2.RawFileType;
				list.Add(folderFileViewModel2);
			}
			return list;
		}

		private FolderFileViewModel createFolderFileViewModel(lenovo.mbg.service.lmsa.phoneManager.Model.FileInfo file)
		{
			if (file == null)
			{
				return null;
			}
			if (file.BooleanIsFolder)
			{
				return new FolderFileViewModel(isFolder: true)
				{
					IsExpanded = false,
					IsSelected = false,
					Path = file.RawFilePath,
					DisplayName = file.RawFileName,
					UpperName = file.RawFileName,
					FileSize = file.LongFileSize,
					UpdateDate = file.DateTimeModifiedDate,
					FileType = file.RawFileType
				};
			}
			return new FolderFileViewModel(isFolder: false)
			{
				IsExpanded = false,
				IsSelected = false,
				Path = file.RawFilePath,
				DisplayName = file.RawFileName,
				UpperName = file.RawFileName,
				FileSize = file.LongFileSize,
				UpdateDate = file.DateTimeModifiedDate,
				FileType = file.RawFileType
			};
		}

		public override char GetDirectorySeparatorChar()
		{
			return '/';
		}

		public override List<FolderFileViewModel> GetRootDirectories()
		{
			string internalPath = string.Empty;
			string externalPath = string.Empty;
			_deviceFileSystemManager.GetInternalAndExternamPath(out internalPath, out externalPath);
			List<FolderFileViewModel> list = new List<FolderFileViewModel>();
			if (!string.IsNullOrEmpty(internalPath) && internalPath.Length > 0 && internalPath[0].Equals('/'))
			{
				FolderFileViewModel folderFileViewModel = new FolderFileViewModel(isFolder: true);
				folderFileViewModel.UpperName = internalPath;
				folderFileViewModel.DisplayName = LangTranslation.Translate("K0592");
				folderFileViewModel.Parent = null;
				folderFileViewModel.IsExpanded = false;
				folderFileViewModel.IsSelected = false;
				folderFileViewModel.Path = internalPath;
				list.Add(folderFileViewModel);
			}
			externalPath = string.Empty;
			if (!string.IsNullOrEmpty(externalPath) && externalPath.Length > 0 && externalPath[0].Equals('/'))
			{
				FolderFileViewModel folderFileViewModel2 = new FolderFileViewModel(isFolder: true);
				folderFileViewModel2.UpperName = externalPath;
				folderFileViewModel2.DisplayName = "K0593";
				folderFileViewModel2.Parent = null;
				folderFileViewModel2.IsExpanded = false;
				folderFileViewModel2.IsSelected = false;
				folderFileViewModel2.Path = externalPath;
				list.Add(folderFileViewModel2);
			}
			return list;
		}

		protected override void OnSelectedChanged(FolderFileViewModel item, bool prevSelected)
		{
			base.OnSelectedChanged(item, prevSelected);
			SelectionHandler?.Invoke(item);
		}

		protected override void DoSearch(FolderFileViewModel node, string keywords, CancellationTokenSource cancellationTokenSource, Action<FolderFileViewModel> itemFoundCallback)
		{
			try
			{
				string empty = string.Empty;
				if (node != null && !string.IsNullOrEmpty(empty = node.Path))
				{
					_deviceFileSystemManager.SearchPhone(empty, keywords, delegate(lenovo.mbg.service.lmsa.phoneManager.Model.FileInfo item)
					{
						itemFoundCallback?.Invoke(createFolderFileViewModel(item));
					});
				}
			}
			catch (Exception)
			{
			}
		}
	}
