		private BitmapImage CreateBitImageAndDisposePrevImage(string path)
		{
			//IL_002a: Unknown result type (might be due to invalid IL or missing references)
			//IL_0030: Expected O, but got Unknown
			if (m_imageFileStream != null)
			{
				try
				{
					m_imageFileStream.Close();
					m_imageFileStream.Dispose();
					m_imageFileStream = null;
				}
				catch (Exception)
				{
				}
			}
			BitmapImage val = new BitmapImage();
			try
			{
				m_imageFileStream = File.OpenRead(path);
				val.BeginInit();
				val.CacheOption = (BitmapCacheOption)1;
				val.StreamSource = m_imageFileStream;
				val.EndInit();
				((Freezable)val).Freeze();
			}
			catch
			{
				val = null;
				val = m_defaultImg;
			}
			return val;
		}

