		private async void DeletePicCommandHandler(object parameter)
		{
			Window win = (Window)((parameter is Window) ? parameter : null);
			LenovoPopupWindow obj = new OkCancelWindowModel().CreateWindow(HostProxy.Host.HostMainWindowHandle, "K0585", "K0562", "K0208", "K0583", (ImageSource)new BitmapImage(new Uri("Pack://application:,,,/lenovo.mbg.service.lmsa.phoneManager;Component/Assets/Images/PicPopup/delete.png")));
			((Window)obj).Owner = win;
			((Window)obj).WindowStartupLocation = (WindowStartupLocation)2;
			((Window)obj).ShowDialog();
			if (!obj.WindowModel.GetViewModel<OKCancelViewModel>().IsOKResult || !(await new DeviceCommonManagement().DeleteDevFilesWithConfirmEx(win, "deletePicturesById", new List<string> { curPicInfoVM.RawPicInfo.Id })))
			{
				return;
			}
			PicInfoViewModel picInfoVM = GetPicInfoVM(isNext: false, isDelete: true);
			if (picInfoVM == null)
			{
				picInfoVM = GetPicInfoVM(isNext: true, isDelete: true);
			}
			if (picInfoVM == null)
			{
				Dispatcher currentDispatcher = HostProxy.CurrentDispatcher;
				if (currentDispatcher != null)
				{
					currentDispatcher.Invoke((Action)delegate
					{
						win.Close();
					});
				}
			}
			else
			{
				ShowPic(picInfoVM);
			}
			PicMgtViewModel.SingleInstance.PicToolRefreshCommandHandler(null);
		}

