			try
			{
				BitmapImage val = new BitmapImage();
				try
				{
					val.BeginInit();
					val.CacheOption = (BitmapCacheOption)1;
					val.UriSource = new Uri(filePath);
					val.EndInit();
				}
				catch
				{
					val = null;
					val = new BitmapImage(new Uri("pack://application:,,,/lenovo.mbg.service.lmsa.phoneManager;component/Assets/Images/pic_default.png", UriKind.RelativeOrAbsolute));
				}
				switch (_currentThumbnailCount)
				{
				case 0:
					_currentThumbnailCount = 1;
					FirstThumbnailImage = (ImageSource)(object)val;
					break;
				case 1:
					_currentThumbnailCount = 2;
					SecondThumbnailImage = (ImageSource)(object)val;
					break;
				case 2:
					_currentThumbnailCount = 3;
					ThirdThumbnailImage = (ImageSource)(object)val;
					break;
				case 3:
					_currentThumbnailCount = 4;
					FourthThumbnailImage = (ImageSource)(object)val;
					break;
				}
			}
			catch (Exception)
