				{
					OneKyCloneSubViewType = ViewType.ONEKEYCLONE;
					ActivectedView.ForEach(delegate(ViewType n)
					{
						Task.Run(delegate
						{
							ViewModelBase obj = Context.FindViewModel<ViewModelBase>(ViewList[n].ViewType, (string)null);
							if (obj != null)
							{
