		public VideoMgtView()
		{
			InitializeComponent();
			if (VideoMgtViewModel.SingleInstance.AlbumViewCallback == null)
			{
				VideoMgtViewModel.SingleInstance.AlbumViewCallback = AlbumViewCallbackHandler;
			}
			VideoMgtViewModel singleInstance = VideoMgtViewModel.SingleInstance;
			object obj = ((FrameworkElement)this).FindResource((object)"DefVedioDrawingImage");
			singleInstance._defaultImage = (ImageSource)((obj is ImageSource) ? obj : null);
			VideoMgtViewModel.SingleInstance.OnDeleteEvent = SetButtonState;
			((FrameworkElement)this).DataContext = VideoMgtViewModel.SingleInstance;
			((Selector)TopCategory).SelectedIndex = 0;
		}

		protected void AlbumViewCallbackHandler(VideoViewType videoViewType)
		{
			switch (videoViewType)
			{
			case VideoViewType.Video:
				ToAlbumVideo();
				break;
			case VideoViewType.Album:
				BackToAlbum(null, null);
				break;
			}
		}

		private void VideoAlbumViewChange(object sender, SelectionChangedEventArgs e)
		{
			VideoMgtViewModel videoMgtViewModel = ((FrameworkElement)this).DataContext as VideoMgtViewModel;
			if (((Selector)TopCategory).SelectedIndex == 0)
			{
				((UIElement)VideoView).Visibility = (Visibility)0;
				((UIElement)AlbumView).Visibility = (Visibility)1;
				((UIElement)spForVideo).Visibility = (Visibility)0;
				((UIElement)btnBack).Visibility = (Visibility)2;
				CheckAllState();
				videoMgtViewModel.MainView = VideoViewType.Video;
				videoMgtViewModel.UpdateVideoList();
			}
			else if (((Selector)TopCategory).SelectedIndex == 1)
			{
				if (videoMgtViewModel.AlbumView == VideoViewType.Album)
				{
					((UIElement)VideoView).Visibility = (Visibility)1;
					((UIElement)AlbumView).Visibility = (Visibility)0;
					((UIElement)spForVideo).Visibility = (Visibility)1;
					((UIElement)btnBack).Visibility = (Visibility)2;
					((UIElement)checkAll).Visibility = (Visibility)2;
				}
				else
				{
					CheckAllState();
					((UIElement)btnBack).Visibility = (Visibility)0;
					videoMgtViewModel.UpdateAlbumVideoList();
				}
				videoMgtViewModel.MainView = VideoViewType.Album;
			}
			videoMgtViewModel.IsAllSelected = !videoMgtViewModel.VideoList.Any((VideoInfoViewModel p) => !p.IsSelected);
			SetButtonState();
		}

		private void CheckAllClick(object sender, RoutedEventArgs e)
		{
			CheckBox cbAll = (CheckBox)((sender is CheckBox) ? sender : null);
			if (cbAll == null || !((ToggleButton)cbAll).IsChecked.HasValue)
			{
				return;
			}
			VideoMgtViewModel.SingleInstance.VideoList.All(delegate(VideoInfoViewModel v)
			{
				v.IsSelected = ((ToggleButton)cbAll).IsChecked.Value;
				return true;
			});
			IconButton obj = btnExport;
			bool isEnabled = (((UIElement)btnDelete).IsEnabled = VideoMgtViewModel.SingleInstance.VideoList.Count != 0 && ((ToggleButton)cbAll).IsChecked.Value);
			((UIElement)obj).IsEnabled = isEnabled;
			if (!((ToggleButton)cbAll).IsChecked.Value && lbTileView.SelectedItems.Count > 0)
			{
				((Selector)lbTileView).SelectedIndex = -1;
			}
			if (VideoMgtViewModel.SingleInstance.MainView == VideoViewType.Video)
			{
				if (((ToggleButton)cbAll).IsChecked.Value)
				{
