		}

		private void SelectAllAblumsPictures(bool _isSelected)
		{
			DevicePicManagementBLLV7 bll = new DevicePicManagementBLLV7();
			Task _task = AsyncDataLoader.Loading((Action)delegate
			{
				foreach (PicAlbumViewModelV7 album in GetCurrentContext.Albums)
				{
					if (album.CachedAllPics.Count == 0)
					{
						bll.RefreshAlbumPicList(album);
					}
					album.IsSelectedAllPic = _isSelected;
				}
				Dispatcher currentDispatcher = HostProxy.CurrentDispatcher;
				if (currentDispatcher != null)
				{
					currentDispatcher.Invoke((Action)delegate
					{
						GetCurrentContext.ReSetPicToolBtnStatus();
						GetCurrentContext.FocusedAlbumClone();
						GetCurrentContext.RefreshPageControlData();
						GetCurrentContext.CheckAllInPagingDataGrid();
						GetCurrentContext.RefreshAllAlbumPicSelectedCount();
					});
				}
				Thread.Sleep(1000);
			});
			Task.Run(delegate
			{
				_task.Wait();
			});
		}

		private void OnCheckBoxSelectAllInAlbum(object sender, RoutedEventArgs e)
		{
			if (GetCurrentContext.FocusedAlbum?.CachedAllPics == null)
			{
				return;
			}
			object obj = ((sender is CheckBox) ? sender : null);
			ObservableCollection<PicInfoViewModelV7> cachedAllPics = GetCurrentContext.FocusedAlbumPaging.CachedAllPics;
			bool valueOrDefault = ((ToggleButton)obj).IsChecked == true;
			foreach (PicInfoViewModelV7 item in cachedAllPics)
			{
				item.IsSelected = valueOrDefault;
			}
			GetCurrentContext.CheckAllInAlbumChecked();
		}

		private void ddlStorageSelect_SelectionChanged(object sender, SelectionChangedEventArgs e)
		{
			if (GetCurrentContext.SdCarVm.IsLoading || GetCurrentContext.SdCarVm.StorageSelIndex < 0)
			{
				return;
			}
			if (GetCurrentContext.IsSelectedInternal)
			{
				GetCurrentContext.PicToolImportBtn.IsEnabled = true;
			}
			else
			{
				GetCurrentContext.PicToolImportBtn.IsEnabled = false;
			}
			GetCurrentContext.PicToolRefreshCommandHandler(null);
			foreach (PicAlbumViewModelV7 album in GetCurrentContext.Albums)
			{
				album.IsSelectedAllPic = false;
			}
		}

