		private void OnCheckBoxSelectAllInAlbum(object sender, RoutedEventArgs e)
		{
			CheckBox val = (CheckBox)((sender is CheckBox) ? sender : null);
			if (val != null && ((ToggleButton)val).IsChecked.HasValue)
			{
				bool _checked = ((ToggleButton)val).IsChecked.Value;
				GetCurrentContext.FocusedAlbumPaging.CachedAllVideos.All(delegate(VideoInfoViewModelV7 v)
				{
					v.IsSelected = _checked;
					return true;
				});
				OperatorButtonViewModelV6 videoToolExportBtn = GetCurrentContext.VideoToolExportBtn;
				bool isEnabled = (GetCurrentContext.VideoToolDeleteBtn.IsEnabled = ((ToggleButton)val).IsChecked.Value);
				videoToolExportBtn.IsEnabled = isEnabled;
				GetCurrentContext.CheckAllInAlbumChecked();
				if (!((ToggleButton)val).IsChecked.Value && lbTileView.SelectedItems.Count > 0)
				{
					((Selector)lbTileView).SelectedIndex = -1;
				}
			}
		}

