	public class MusicInfo : ViewModelBase
	{
		private bool _isSeleted;

		public int ID { get; set; }

		public string AlbumID { get; set; }

		public string Name { get; set; }

		public string DisplayName { get; set; }

		public string Artist { get; set; }

		public string Album { get; set; }

		public string AlbumName => Path.GetFileName(AlbumPath);

		public string AlbumPath { get; set; }

		public long Size { get; set; }

		public int Duration { get; set; }

		public string DurationString => new TimeSpan(0, 0, Duration / 1000).ToString("mm\\:ss");

		public string ModifiedDate { get; set; }

		public DateTime DModifiedDate { get; set; }

		public double Frequency { get; set; }

		public string FilePath { get; set; }

		public ServerMusicInfo RawMusicInfo { get; set; }

		private MusicMgtViewModelV7 GetCurrentViewModel => Context.FindViewModel<MusicMgtViewModelV7>(typeof(MusicMgtViewV7), (string)null);

		public bool IsNotUserClick { get; set; }

		[JsonIgnore]
		public bool IsSelected
		{
			get
			{
				return _isSeleted;
			}
			set
			{
				if (_isSeleted != value)
				{
					_isSeleted = value;
					if (!IsNotUserClick)
					{
						SingleMouseClickCommandHandler();
					}
					((NotifyBase)this).OnPropertyChanged("IsSelected");
				}
			}
		}

		public bool IsInternalPath
		{
			get
			{
				if (HostProxy.deviceManager.MasterDevice.ConnectedAppType == "Moto")
				{
					return true;
				}
				return RawMusicInfo.AlbumID.StartsWith("/storage/emulated/0");
			}
		}

		private void SingleMouseClickCommandHandler()
		{
			MusicAlbumViewModelV7 focusedAlbumPaging = GetCurrentViewModel.FocusedAlbumPaging;
			MusicAlbumViewModelV7 focusedAlbum = GetCurrentViewModel.FocusedAlbum;
			if (IsSelected)
			{
				if (focusedAlbumPaging.CachedAllMusics.Count((MusicInfo m) => !m.IsSelected) > 0)
				{
					focusedAlbumPaging.IsSelectedAllMusics = null;
					focusedAlbum.IsSelectedAllMusics = null;
					GetCurrentViewModel.IsSelectedAllAlbumMusic = null;
				}
				else
				{
					focusedAlbumPaging.IsSelectedAllMusics = true;
					if (focusedAlbum.CachedAllMusics.Count((MusicInfo m) => !m.IsSelected) == 0)
					{
						focusedAlbum.IsSelectedAllMusics = true;
					}
					if (GetCurrentViewModel.Albums.Count((MusicAlbumViewModelV7 m) => m.IsSelectedAllMusics != true) == 0)
					{
						GetCurrentViewModel.IsSelectedAllAlbumMusic = true;
					}
				}
			}
			else if (focusedAlbumPaging.CachedAllMusics.Count((MusicInfo m) => m.IsSelected) > 0)
			{
				focusedAlbumPaging.IsSelectedAllMusics = null;
				focusedAlbum.IsSelectedAllMusics = null;
				GetCurrentViewModel.IsSelectedAllAlbumMusic = null;
			}
			else
			{
				focusedAlbumPaging.IsSelectedAllMusics = false;
				if (focusedAlbum.CachedAllMusics.Count((MusicInfo m) => m.IsSelected) == 0)
				{
					focusedAlbum.IsSelectedAllMusics = false;
				}
				if (GetCurrentViewModel.Albums.Count((MusicAlbumViewModelV7 m) => m.IsSelectedAllMusics != false) == 0)
				{
					GetCurrentViewModel.IsSelectedAllAlbumMusic = false;
				}
			}
			GetCurrentViewModel.RefreshAllAlbumMusicSelectedCount();
		}
	}
