	public class SingleObjectConverter : IValueConverter
	{
		public object Convert(object value, Type targetType, object parameter, CultureInfo culture)
		{
			string[] array = parameter.ToString().Split(new char[1] { ':' });
			if (value == null)
			{
				return array[2];
			}
			if (array[0].Contains("|"))
			{
				if (!Enumerable.Contains(array[0].ToLower().Split(new char[1] { '|' }), value.ToString().ToLower()))
				{
					return array[2];
				}
				return array[1];
			}
			if (!array[0].ToLower().Equals(value.ToString().ToLower()))
			{
				return array[2];
			}
			return array[1];
		}

		public object ConvertBack(object value, Type targetType, object parameter, CultureInfo culture)
		{
			string result = "otherValue";
			string[] array = parameter.ToString().ToLower().Split(new char[1] { ':' });
			if (value == null)
			{
				return result;
			}
			if (value.ToString().ToLower() != array[1])
			{
				return result;
			}
			if (!Enumerable.Contains(array[0], '|'))
			{
				return array[0];
			}
			return array[0].Split(new char[1] { '|' })[0];
		}
	}
	public class InvertBoolConverter : IValueConverter
	{
		public object Convert(object value, Type targetType, object parameter, CultureInfo culture)
		{
			string text = parameter as string;
			if (string.IsNullOrEmpty(text) || text.Split(new char[1] { ':' }).Length != 3)
			{
				if (value == null || !bool.TryParse(value.ToString(), out var result))
				{
					return false;
				}
				return !result;
			}
			string[] array = text.Split(new char[1] { ':' });
			if (value == null)
			{
				return array[2];
			}
			if (!(value.ToString() == array[0]))
			{
				return array[2];
			}
			return array[1];
		}

		public object ConvertBack(object value, Type targetType, object parameter, CultureInfo culture)
		{
			string text = parameter as string;
			if (string.IsNullOrEmpty(text) || text.Split(new char[1] { ':' }).Length != 3)
			{
				if (value == null || !bool.TryParse(value.ToString(), out var result))
				{
					return true;
				}
				return !result;
			}
			string[] array = text.Split(new char[1] { ':' });
			if (value == null)
			{
				return false;
			}
			return value.ToString() == array[1];
		}
	}
