		public static TreeViewItem GetLogicTree(DependencyObject dobj)
		{
			//IL_0005: Unknown result type (might be due to invalid IL or missing references)
			//IL_000a: Unknown result type (might be due to invalid IL or missing references)
			//IL_0016: Unknown result type (might be due to invalid IL or missing references)
			//IL_001e: Expected O, but got Unknown
			if (dobj == null)
			{
				return null;
			}
			TreeViewItem val = new TreeViewItem
			{
				Header = GetTypeDescription(dobj),
				IsExpanded = true
			};
			foreach (object child in LogicalTreeHelper.GetChildren(dobj))
			{
				TreeViewItem logicTree = GetLogicTree((DependencyObject)((child is DependencyObject) ? child : null));
				if (logicTree != null)
				{
					((ItemsControl)val).Items.Add((object)logicTree);
				}
			}
			return val;
		}

		public static TreeViewItem GetVisualTree(DependencyObject dobj)
		{
