	public class DeviceCommonManagement
	{
		public bool AnalysisResult(string jsonResultString, string valueKey)
		{
			List<PropItem> list = JsonUtils.Parse<List<PropItem>>(jsonResultString);
			if (list != null)
			{
				string text = (from m in list
					where valueKey.Equals(m.Key)
					select m.Value).FirstOrDefault();
				if (!string.IsNullOrEmpty(text) && "true".Equals(text.ToLower()))
				{
					return true;
				}
			}
			return false;
		}

		public bool CheckInternalStorageFreeSize(MessageReaderAndWriter msgRWHander, List<string> filePaths)
		{
			long result = 0L;
			List<PropItem> list = null;
			if (msgRWHander.SendAndReceiveSync<string, PropItem>("getInternalStorageInfo", "getInternalStorageInfoResponse", new List<string>(), Sequence.SingleInstance.New(), ref list) && list != null)
			{
				foreach (PropItem item in list)
				{
					if (item.Key.Equals("free"))
					{
						long.TryParse(item.Value, out result);
					}
				}
			}
			return FileSizeCalculationHelper.GetFilesSize(filePaths) > result;
		}

		public async Task<List<int>> DeleteDevFiles(string delCommandStr, List<string> fileIdArr)
		{
			if (fileIdArr == null || fileIdArr.Count == 0)
			{
				return null;
			}
			DeviceEx masterDevice = HostProxy.deviceManager.MasterDevice;
			TcpAndroidDevice dev = (TcpAndroidDevice)(object)((masterDevice is TcpAndroidDevice) ? masterDevice : null);
			TcpAndroidDevice obj = dev;
			if (((obj != null) ? obj.MessageManager : null) == null)
			{
				return null;
			}
			List<int> _retList = null;
			await AsyncDataLoader.Loading((Action)delegate
			{
				MessageReaderAndWriter val = dev.MessageManager.CreateMessageReaderAndWriter(0);
				try
				{
					if (val != null)
					{
						if (HostProxy.deviceManager.IsMasterConnectedByHelperForAndroid11())
						{
							_retList = DeleteFileOneByOne(val, delCommandStr, fileIdArr);
						}
						else
						{
							_retList = DeleteMultiFile(val, delCommandStr, fileIdArr);
						}
					}
				}
				finally
				{
					((IDisposable)val)?.Dispose();
				}
			});
			return _retList;
		}

		private List<int> DeleteMultiFile(MessageReaderAndWriter wr, string delCommandStr, List<string> fileIdArr, int max = 2000)
		{
			int num = 0;
			List<string> list = null;
			List<int> list2 = new List<int>();
			long num2 = HostProxy.Sequence.New();
			while (true)
			{
				list = fileIdArr.Skip(num++ * max).Take(max).ToList();
				if (list.Count == 0)
				{
					break;
				}
				MessageEx<int> val = wr.SendAndReceive(delCommandStr, list, num2);
				if (val == null || val.Action != delCommandStr + "Response")
				{
					for (int i = 0; i < list.Count; i++)
					{
						list2.Add(1);
					}
				}
				else
				{
					list2.AddRange(val.Data);
				}
			}
			return list2;
		}

		private List<int> DeleteFileOneByOne(MessageReaderAndWriter wr, string delCommandStr, List<string> fileIdArr)
		{
			List<string> list = new List<string>();
			List<int> list2 = new List<int>();
			long num = HostProxy.Sequence.New();
			foreach (string item in fileIdArr)
			{
				list.Clear();
				list.Add(item);
				MessageEx<int> val = wr.SendAndReceive(delCommandStr, list, num);
				if (val == null || val.Action != delCommandStr + "Response")
				{
					list2.Add(1);
				}
				else
				{
					list2.AddRange(val.Data);
				}
			}
			return list2;
		}

		public async Task<Tuple<bool, Dictionary<string, int>>> DeleteDevFilesWithConfirm(string delCommandStr, List<string> fileIdArr, Dictionary<string, int> result)
		{
			if (result.Count == 0)
			{
				result = new Dictionary<string, int>
				{
					{ "success", 0 },
					{ "failed", 0 },
					{ "confirm", 0 }
				};
			}
			List<int> arr = await DeleteDevFiles(delCommandStr, fileIdArr);
			if (arr == null)
			{
				return new Tuple<bool, Dictionary<string, int>>(item1: false, result);
			}
			int scount = arr.Where((int p) => p == 0).Count();
			int fcount = arr.Where((int p) => p == 1).Count();
			int rcount = arr.Where((int p) => p == 2).Count();
			result["success"] += scount;
			result["failed"] += fcount;
			result["confirm"] += rcount;
			if (fcount == 0 && rcount == 0)
			{
				return new Tuple<bool, Dictionary<string, int>>(item1: true, result);
			}
			DeleteResultWindowV6 win = null;
			HostProxy.CurrentDispatcher.Invoke((Action)delegate
			{
				win = new DeleteResultWindowV6(scount, fcount, rcount);
				if (rcount == 0)
				{
					((UIElement)win.btnGoOn).Visibility = (Visibility)2;
					((ContentControl)win.btnCancel).Content = "K0327";
					((UIElement)win.txtWarning).Visibility = (Visibility)2;
				}
			});
			if (await MessageWindowHelper.Instance.Show((IMessageWindowV6)(object)win, (bool?)true) != true)
			{
				return new Tuple<bool, Dictionary<string, int>>(item1: false, result);
			}
			for (int num = fileIdArr.Count - 1; num >= 0; num--)
			{
				if (arr[num] == 0)
				{
					fileIdArr.RemoveAt(num);
				}
			}
			return await DeleteDevFilesWithConfirm(delCommandStr, fileIdArr, result);
		}

		public async Task<bool> DeleteDevFilesWithConfirmEx(Window ower, string delCommandStr, List<string> fileIdArr)
		{
			List<int> arr = await DeleteDevFiles(delCommandStr, fileIdArr);
			if (arr == null)
			{
				return false;
			}
			int success = arr.Where((int p) => p == 0).Count();
			int num = arr.Where((int p) => p == 1).Count();
			int num2 = arr.Where((int p) => p == 2).Count();
			if (num == 0 && num2 == 0)
			{
				return true;
			}
			DeleteResultWindowV6 deleteResultWindowV = new DeleteResultWindowV6(success, num, num2);
			((Window)deleteResultWindowV).Owner = ower;
			((Window)deleteResultWindowV).WindowStartupLocation = (WindowStartupLocation)2;
			if (await MessageWindowHelper.Instance.Show((IMessageWindowV6)(object)deleteResultWindowV, (bool?)true) != true)
			{
				return false;
			}
			for (int num3 = fileIdArr.Count - 1; num3 >= 0; num3--)
			{
				if (arr[num3] == 0)
				{
					fileIdArr.RemoveAt(num3);
				}
			}
			return await DeleteDevFilesWithConfirmEx(ower, delCommandStr, fileIdArr);
		}
	}
	public class DataPartitionWrapper
	{
		public static void DoProcess<T>(IEnumerable<T> datas, int partitionCount, Func<IEnumerable<T>, bool> callBack)
		{
			int num = 0;
			while (true)
			{
				IEnumerable<T> enumerable = datas.Skip(num * partitionCount).Take(partitionCount);
				if (enumerable.Count() != 0 && callBack(enumerable))
				{
					num++;
					continue;
				}
				break;
			}
		}
	}
