					long num = HostProxy.Sequence.New();
					int num2 = 0;
					int count = ids.Count;
					List<string> list = new List<string>();
					string text = Path.Combine(loacalDir, "contacts_" + DateTime.Now.ToString("yyyyMMddHHmmss") + ".vcf");
					HostProxy.ResourcesLoggingService.RegisterFile(text);
					if (!val2.TryEnterLock(10000))
					{
						return false;
					}
					try
					{
						using FileStream fileStream = new FileStream(text, FileMode.CreateNew, FileAccess.ReadWrite);
						while (flag && num2 < count)
						{
							List<string> list2 = new List<string>();
							while (num2 < count)
							{
								list2.Add(ids[num2]);
								if (++num2 % 50 == 0)
								{
									break;
								}
							}
							if (!(flag &= val2.Send<string>("exportContacts", list2.ToList(), num)))
							{
								continue;
							}
							FileTransferWrapper val3 = fileTransferManager.CreateFileTransfer(num);
							try
							{
								if (val3 == null)
								{
									return false;
								}
								TransferFileInfo val4 = null;
								val3.ReceiveFile(loacalDir, ref val4);
								if (File.Exists(val4.localFilePath))
								{
									string text2 = Path.Combine(loacalDir, val4.VirtualFileName);
									list.Add(text2);
									byte[] bytes = Encoding.UTF8.GetBytes(File.ReadAllText(text2));
									fileStream.Write(bytes, 0, bytes.Length);
									File.Delete(text2);
								}
							}
							finally
							{
								((IDisposable)val3)?.Dispose();
							}
							List<PropItem> list3 = null;
							flag = (flag &= val2.Receive<PropItem>("exportContactsResponse", ref list3, 15000) && list3 != null) && (flag & list3.Exists((PropItem m) => "true".Equals(m.Value)));
						}
					}
					finally
					{
						foreach (string item in list)
						{
							try
							{
								File.Delete(item);
							}
							catch (Exception)
							{
							}
						}
						val2.ExitLock();
					}
				}
				finally
				{
					((IDisposable)val2)?.Dispose();
				}
			}
			return flag;
		}

