		public bool ExportThumbnailFromDevice(IAsyncTaskContext context, List<ServerPicInfo> pics, string localStroageDir, Action<ServerPicInfo, bool> callBack, CancellationTokenSource cancelSource)
		{
			if (pics == null || pics.Count == 0)
			{
				return false;
			}
			DeviceEx masterDevice = HostProxy.deviceManager.MasterDevice;
			TcpAndroidDevice val = (TcpAndroidDevice)(object)((masterDevice is TcpAndroidDevice) ? masterDevice : null);
			if (val == null)
			{
				return false;
			}
			MessageReaderAndWriter val2 = val.MessageManager.CreateMessageReaderAndWriter(0);
			try
			{
				if (val2 == null)
				{
					return false;
				}
				IFileTransferManager fileTransferManager = val.FileTransferManager;
				long num = HostProxy.Sequence.New();
				if (!val2.TryEnterLock(10000))
				{
					return false;
				}
				try
				{
					List<string> list = pics.Select((ServerPicInfo m) => m.Id).ToList();
					if (val2.Send<string>("exportPICThumbnail", list, num))
					{
						bool result = false;
						try
						{
							FileTransferWrapper val3 = fileTransferManager.CreateFileTransfer(num);
							try
							{
								if (val3 == null)
								{
									return false;
								}
								int count = list.Count;
								TransferFileInfo recvFileInfo = null;
								bool flag = false;
								for (int num2 = 0; num2 < count; num2++)
								{
									if (cancelSource?.IsCancellationRequested == true)
									{
										flag = false;
										break;
									}
									flag = val3.ReceiveFile(localStroageDir, ref recvFileInfo);
									val3.NotifyFileReceiveComplete();
									if (callBack != null)
									{
										ServerPicInfo serverPicInfo = pics.FirstOrDefault(delegate(ServerPicInfo p)
										{
											string id = p.Id;
											TransferFileInfo obj = recvFileInfo;
											return id.Equals((obj != null) ? obj.FilePath : null);
										});
										if (serverPicInfo == null)
										{
											callBack(null, arg2: false);
											continue;
										}
										serverPicInfo.LocalFilePath = Path.Combine(localStroageDir, recvFileInfo.VirtualFileName);
										callBack(serverPicInfo, flag);
									}
								}
							}
							finally
							{
								((IDisposable)val3)?.Dispose();
							}
						}
						finally
						{
							List<PropItem> list2 = null;
							if (val2.Receive<PropItem>("exportPICThumbnailResponse", ref list2, 15000) && list2 != null)
							{
								result = list2.Exists((PropItem m) => "true".Equals(m.Value));
							}
						}
						return result;
					}
					return false;
				}
				finally
				{
					val2.ExitLock();
				}
			}
			finally
			{
				((IDisposable)val2)?.Dispose();
			}
		}

