		public bool Export(TcpAndroidDevice currentDevice, string apk, string savePath, Action<string, bool> callback)
		{
			return Export(currentDevice, new List<string> { apk }, savePath, callback, null);
		}

		public bool Export(TcpAndroidDevice currentDevice, List<string> apks, string savePath, Action<string, bool> callback, IAsyncTaskContext context)
		{
			if (currentDevice == null)
			{
				return false;
			}
			MessageReaderAndWriter msgRWriter = currentDevice.MessageManager.CreateMessageReaderAndWriter(0);
			try
			{
				if (msgRWriter == null)
				{
					return false;
				}
				context.AddCancelSource((Action)delegate
				{
					msgRWriter.Dispose();
				});
				IFileTransferManager fileTransferManager = currentDevice.FileTransferManager;
				long num = HostProxy.Sequence.New();
				try
				{
					if (msgRWriter.Send<string>("exportApks", apks, num))
					{
						bool result = false;
						try
						{
							FileTransferWrapper fileTransfer = fileTransferManager.CreateFileTransfer(num);
							try
							{
								context.AddCancelSource((Action)delegate
								{
									fileTransfer.Dispose();
								});
								if (fileTransfer == null)
								{
									return false;
								}
								int count = apks.Count;
								TransferFileInfo val = null;
								bool flag = false;
								for (int num2 = 0; num2 < count; num2++)
								{
									if (context.IsCancelCommandRequested)
									{
										break;
									}
									flag = fileTransfer.ReceiveFile(savePath, ref val);
									if (callback != null)
									{
										string virtualFileName = val.VirtualFileName;
										HostProxy.ResourcesLoggingService.RegisterFile(val.localFilePath);
										callback(virtualFileName, flag);
									}
									fileTransfer.NotifyFileReceiveComplete();
								}
							}
							finally
							{
								if (fileTransfer != null)
								{
									((IDisposable)fileTransfer).Dispose();
								}
							}
						}
						finally
						{
							List<PropItem> list = null;
							if (msgRWriter.Receive<PropItem>("exportApksResponse", ref list, 15000) && list != null)
							{
								result = list.Exists((PropItem m) => "true".Equals(m.Value));
							}
						}
						return result;
					}
					return false;
				}
				finally
				{
					msgRWriter.ExitLock();
				}
			}
			finally
			{
				if (msgRWriter != null)
				{
					((IDisposable)msgRWriter).Dispose();
				}
			}
		}

