		public bool Import(TcpAndroidDevice currentDevice, List<string> apkPath, Action<string, bool> callback)
		{
			if (currentDevice == null)
			{
				return false;
			}
			MessageReaderAndWriter val = currentDevice.MessageManager.CreateMessageReaderAndWriter(0);
			try
			{
				if (val == null)
				{
					return false;
				}
				IFileTransferManager fileTransferManager = currentDevice.FileTransferManager;
				long num = HostProxy.Sequence.New();
				if (CheckInternalStorageFreeSize(val, apkPath))
				{
					return false;
				}
				if (!val.TryEnterLock(10000))
				{
					return false;
				}
				try
				{
					bool result = false;
					try
					{
						if (val.Send<string>("importInstallApk", new List<string> { apkPath.Count.ToString() }, num))
						{
							FileTransferWrapper val2 = fileTransferManager.CreateFileTransfer(num);
							try
							{
								if (val2 == null)
								{
									return false;
								}
								bool flag = false;
								foreach (string item in apkPath)
								{
									flag = val2.SendFile(item, num);
									callback?.Invoke(item, flag);
									val2.WaitFileReceiveCompleteNotify(13000);
								}
							}
							finally
							{
								((IDisposable)val2)?.Dispose();
							}
						}
					}
					finally
					{
						List<PropItem> list = null;
						if (val.Receive<PropItem>("importInstallApkResponse", ref list, 15000))
						{
							result = list.Exists((PropItem m) => "true".Equals(m.Value));
						}
					}
					return result;
				}
				finally
				{
					val.ExitLock();
				}
			}
			finally
			{
				((IDisposable)val)?.Dispose();
			}
		}

