		private int InstallWithAdb(TcpAndroidDevice currentDevice, string apkPath)
		{
			if (currentDevice == null)
			{
				return 0;
			}
			string text = RunCmdIfDeviceExist(((DeviceEx)currentDevice).Identifer, $"install -r \"{apkPath}\"", -1);
			LogHelper.LogInstance.Debug($"adb Install apk[{apkPath}],the response:{text}", false);
			string text2 = text.ToUpper();
			if (text2.Contains("SUCCESS"))
			{
				return 1;
			}
			if (text2.Contains("INSTALL_FAILED_INSUFFICIENT_STORAGE") || text2.Contains("INSTALL_FAILED_CONTAINER_ERROR"))
			{
				return -1;
			}
			return 0;
		}

		public static string RunCmdIfDeviceExist(string deviceId, string sourceCommand, int timeout)
		{
			string text = Path.Combine(Environment.SystemDirectory, "cmd.exe");
			string text2 = string.Format("/c (\"{0}\" devices | findstr \"{1}\" && \"{0}\" -s \"{1}\" {2})", Path.Combine(Environment.CurrentDirectory, "adb.exe"), deviceId, sourceCommand);
			return ProcessHelper.Instance.Do(text, text2, timeout);
		}

