		public async Task<List<int>> DeleteDevFiles(string delCommandStr, List<string> fileIdArr, int max = 50)
		{
			if (fileIdArr == null || fileIdArr.Count == 0)
			{
				return null;
			}
			DeviceEx masterDevice = HostProxy.deviceManager.MasterDevice;
			TcpAndroidDevice dev = (TcpAndroidDevice)(object)((masterDevice is TcpAndroidDevice) ? masterDevice : null);
			TcpAndroidDevice obj = dev;
			if (((obj != null) ? obj.MessageManager : null) == null)
			{
				return null;
			}
			List<int> _retList = null;
			await AsyncDataLoader.Loading((Action)delegate
			{
				MessageReaderAndWriter val = dev.MessageManager.CreateMessageReaderAndWriter(0);
				try
				{
					if (val != null)
					{
						if (HostProxy.deviceManager.IsMasterConnectedByHelperForAndroid11())
						{
							_retList = DeleteFileOneByOne(val, delCommandStr, fileIdArr);
						}
						else
						{
							_retList = DeleteMultiFile(val, delCommandStr, fileIdArr);
						}
					}
				}
				finally
				{
					((IDisposable)val)?.Dispose();
				}
			});
			return _retList;
		}

		private List<int> DeleteMultiFile(MessageReaderAndWriter wr, string delCommandStr, List<string> fileIdArr, int max = 50)
		{
			int num = 0;
			List<string> list = null;
			List<int> list2 = new List<int>();
			long num2 = HostProxy.Sequence.New();
			while (true)
			{
				list = fileIdArr.Skip(num++ * max).Take(max).ToList();
				if (list.Count == 0)
				{
					break;
				}
				MessageEx<int> val = wr.SendAndReceive(delCommandStr, list, num2);
				if (val == null || val.Action != delCommandStr + "Response")
				{
					for (int i = 0; i < list.Count; i++)
					{
						list2.Add(1);
					}
				}
				else
				{
					list2.AddRange(val.Data);
				}
			}
			return list2;
		}

		private List<int> DeleteFileOneByOne(MessageReaderAndWriter wr, string delCommandStr, List<string> fileIdArr)
		{
			List<string> list = new List<string>();
			List<int> list2 = new List<int>();
			long num = HostProxy.Sequence.New();
			foreach (string item in fileIdArr)
			{
				list.Clear();
				list.Add(item);
				MessageEx<int> val = wr.SendAndReceive(delCommandStr, list, num);
				if (val == null || val.Action != delCommandStr + "Response")
				{
					list2.Add(1);
				}
				else
				{
					list2.AddRange(val.Data);
				}
			}
			return list2;
		}

		public async Task<Tuple<bool, Dictionary<string, int>>> DeleteDevFilesWithConfirm(string delCommandStr, List<string> fileIdArr, Dictionary<string, int> result)
		{
			if (result.Count == 0)
			{
				result = new Dictionary<string, int>
				{
					{ "success", 0 },
					{ "failed", 0 },
					{ "confirm", 0 }
				};
			}
			List<int> arr = await DeleteDevFiles(delCommandStr, fileIdArr);
			if (arr == null)
			{
				return new Tuple<bool, Dictionary<string, int>>(item1: false, result);
			}
			int scount = arr.Where((int p) => p == 0).Count();
			int fcount = arr.Where((int p) => p == 1).Count();
			int rcount = arr.Where((int p) => p == 2).Count();
			result["success"] += scount;
			result["failed"] += fcount;
			result["confirm"] += rcount;
			if (fcount == 0 && rcount == 0)
			{
				return new Tuple<bool, Dictionary<string, int>>(item1: true, result);
			}
			DeleteResultWindowV6 _resultWindow = null;
			HostProxy.CurrentDispatcher.Invoke((Action)delegate
			{
				_resultWindow = new DeleteResultWindowV6(scount, fcount, rcount);
				if (rcount == 0)
				{
					((UIElement)_resultWindow.btnGoOn).Visibility = (Visibility)2;
					((ContentControl)_resultWindow.btnCancel).Content = "K0327";
					((UIElement)_resultWindow.txtWarning).Visibility = (Visibility)2;
				}
			});
			if (await MessageWindowHelper.Instance.Show((IMessageWindowV6)(object)_resultWindow, (bool?)true) != true)
			{
				return new Tuple<bool, Dictionary<string, int>>(item1: false, result);
			}
			for (int num = fileIdArr.Count - 1; num >= 0; num--)
			{
				if (arr[num] == 0)
				{
					fileIdArr.RemoveAt(num);
				}
			}
			return await DeleteDevFilesWithConfirm(delCommandStr, fileIdArr, result);
		}

		public static async Task<List<string>> CheckImportFiles(List<string> _importFiles)
		{
			if (_importFiles == null || _importFiles.Count == 0)
			{
				return new List<string>();
			}
			List<string> list = new List<string>();
			foreach (string _importFile in _importFiles)
			{
				System.IO.FileInfo fileInfo = new System.IO.FileInfo(_importFile);
				if (fileInfo.Length > 4294967296L)
				{
					list.Add(_importFile);
					LogHelper.LogInstance.Warn("The file is larger than 4G in size. file:[" + _importFile + "] size:[" + GlobalFun.ConvertLong2String(fileInfo.Length, "F1", true) + "].", false);
				}
			}
			if (list.Count > 0)
			{
				list.ForEach(delegate(string m)
				{
					_importFiles.Remove(m);
				});
				File.WriteAllText(Configurations.TRANSFER_FILE_ERROR_TXT_PATH, string.Join(Environment.NewLine, list));
				Larger4GBDialogView val = new Larger4GBDialogView(2);
				await MessageWindowHelper.Instance.Show((IMessageViewV6)(object)val, false, false, (Action<IMessageWindowV6>)null, (Predicate<object>)null, (Predicate<object>)null, (Func<bool>)null, (bool?)true);
			}
			return _importFiles;
		}

		public static async void CheckExportFiles(Dictionary<string, long> _exportFiles)
		{
			if (_exportFiles.Count > 0)
			{
				File.WriteAllText(Configurations.TRANSFER_FILE_ERROR_TXT_PATH, string.Join(Environment.NewLine, _exportFiles.Keys));
				Larger4GBDialogView val = new Larger4GBDialogView(1);
				await MessageWindowHelper.Instance.Show((IMessageViewV6)(object)val, false, false, (Action<IMessageWindowV6>)null, (Predicate<object>)null, (Predicate<object>)null, (Func<bool>)null, (bool?)true);
			}
		}
	}
